// JavaScript follows standard math order of operations
console.log(2 + 3 * 4);      // 14 (not 20!) — multiplication first
console.log((2 + 3) * 4);    // 20 — parentheses override

// Order: Parentheses → Exponents → Multiply/Divide → Add/Subtract
console.log(10 + 20 / 2);    // 20 — division first: 10 + 10
console.log((10 + 20) / 2);  // 15 — parentheses first: 30 / 2

// When in doubt, use parentheses to make it clear!
let total = (price * quantity) + tax; // Clear intent

