// UNDEFINED — JavaScript's default "no value"
let uninitializedVar;
console.log(uninitializedVar); // undefined
// JavaScript says: "You made this box but never put anything in it."

// NULL — Your intentional "empty"
let selectedUser = null;
console.log(selectedUser); // null
// You're saying: "This box is intentionally empty. No user is selected yet."

// Later, when a user is selected:
selectedUser = { name: "Alice" };
// Now the box has a value!

// typeof tells you what type a value is
console.log(typeof 42);          // "number"
console.log(typeof "hello");     // "string"
console.log(typeof true);        // "boolean"
console.log(typeof undefined);   // "undefined"
console.log(typeof null);        // "object" ← THIS IS A BUG!
console.log(typeof {});          // "object"

// Using typeof with variables
let score = 100;
console.log(typeof score); // "number"

