console.log(true == 1);    // true  (true becomes 1, then 1 == 1)
console.log(null == undefined); // true (special case)
console.log("" == 0);      // true  ("" becomes 0, then 0 == 0)

// 🚨 ALWAYS use === unless you have a SPECIFIC reason not to

