// && returns true ONLY if BOTH sides are true
console.log(true && true);   // true
console.log(true && false);  // false
console.log(false && true);  // false
console.log(false && false); // false

// Real example: Can the user access premium content?
const isLoggedIn = true;
const hasSubscription = true;
const canAccessPremium = isLoggedIn && hasSubscription;
console.log(canAccessPremium); // true — both conditions met!

// Age must be between 13 and 65
const age = 25;
const isValidAge = age >= 13 && age <= 65;
console.log(isValidAge); // true

// || returns true if AT LEAST ONE side is true
console.log(true || true);   // true
console.log(true || false);  // true
console.log(false || true);  // true
console.log(false || false); // false

// Real example: Can the user get a discount?
const isStudent = false;
const isSenior = true;
const getsDiscount = isStudent || isSenior;
console.log(getsDiscount); // true — at least one is true!

// Valid payment method?
const hasCard = false;
const hasPayPal = false;
const hasCrypto = true;
const canPay = hasCard || hasPayPal || hasCrypto;
console.log(canPay); // true

// ! flips true to false and false to true
console.log(!true);  // false
console.log(!false); // true

// Real example: Is the user NOT banned?
const isBanned = false;
const canPost = !isBanned;
console.log(canPost); // true — not banned, so can post!

// Double NOT (!!) converts to boolean
console.log(!!"hello"); // true ("hello" is truthy)
console.log(!!0);       // false (0 is falsy)
console.log(!!null);    // false (null is falsy)

