console.log("Have a great day!"); // This ALWAYS runs

let age = 16;

if (age >= 18) {
    console.log("You can vote! 🗳️");
    console.log("You can also drive.");
} else {
    console.log("You're not old enough to vote yet.");
    console.log(`Wait ${18 - age} more year(s).`);
}

// Output:
// "You're not old enough to vote yet."
// "Wait 2 more year(s)."

let score = 85;
let grade;

if (score >= 90) {
    grade = "A";
} else if (score >= 80) {
    grade = "B";
} else if (score >= 70) {
    grade = "C";
} else if (score >= 60) {
    grade = "D";
} else {
    grade = "F";
}

console.log(`Your score is ${score}. Grade: ${grade}`); 
// "Your score is 85. Grade: B"

sections.content:
Watch what happens if we reverse the order:

```javascript
if (score >= 60) {
    grade = "D"; // Score 85 would match here first!
} else if (score >= 70) {
    grade = "C"; // Never reached for 85+
}
```

Since 85 >= 60 is true, it stops there and assigns "D". That's wrong! Always put the most specific (strictest) conditions first.

