// Version 1: Only prints (can't use the result)
function addAndPrint(a, b) {
  console.log(a + b);  // Shows the result, but it's "gone"
}

let result1 = addAndPrint(3, 4);  // Prints: 7
console.log(result1);  // undefined! The function didn't return anything.

// Version 2: Returns (the result is usable)
function add(a, b) {
  return a + b;  // Sends the result back
}

let result2 = add(3, 4);  // result2 is now 7
console.log(result2);     // 7
console.log(add(10, 20)); // 30

// Now we can USE the returned value!
let total = add(5, 3) + add(10, 2);  // 8 + 12 = 20
console.log(total);  // 20

function checkAge(age) {
  if (age < 0) {
    return "Invalid age";  // Exits immediately
  }
  if (age < 18) {
    return "Minor";  // Exits here if this runs
  }
  return "Adult";  // Only reached if age >= 18

  console.log("This line NEVER runs!");  // Dead code
}

console.log(checkAge(25));  // "Adult"
console.log(checkAge(12));  // "Minor"
console.log(checkAge(-5));  // "Invalid age"

function celsiusToFahrenheit(celsius) {
  return (celsius * 9/5) + 32;
}

function formatTemperature(tempF) {
  return tempF.toFixed(1) + "°F";
}

// Chain them together!
let tempC = 37;
let tempF = celsiusToFahrenheit(tempC);
let display = formatTemperature(tempF);
console.log(display);  // "98.6°F"

// Or in one line:
console.log(formatTemperature(celsiusToFahrenheit(100)));  // "212.0°F"

