// Traditional function declaration
function add(a, b) {
  return a + b;
}

// Arrow function (stored in a variable)
const addArrow = (a, b) => {
  return a + b;
};

// Concise arrow function (one-liner: implicit return)
const addShort = (a, b) => a + b;

// All three work the same way:
console.log(add(2, 3));       // 5
console.log(addArrow(2, 3));  // 5
console.log(addShort(2, 3));  // 5

// One parameter: parentheses optional
const double = n => n * 2;
console.log(double(7)); // 14

// Zero parameters: parentheses required
const greet = () => "Hello!";
console.log(greet()); // "Hello!"

// Multiple parameters: parentheses required
const multiply = (a, b) => a * b;
console.log(multiply(3, 4)); // 12

// Multi-line body: braces and return required
const describePerson = (name, age) => {
  let category = age >= 18 ? "adult" : "minor";
  return name + " is a(n) " + category;
};
console.log(describePerson("Alice", 25)); // "Alice is a(n) adult"

