// Basic operations
const add = (a, b) => a + b;
const subtract = (a, b) => a - b;
const multiply = (a, b) => a * b;
const divide = (a, b) => {
  if (b === 0) return "Error: Division by zero";
  return a / b;
};

// Higher-order calculator function
function calculate(a, b, operation) {
  return operation(a, b);
}

console.log(calculate(10, 5, add));       // 15
console.log(calculate(10, 5, subtract));  // 5
console.log(calculate(10, 5, multiply));  // 50
console.log(calculate(10, 0, divide));    // "Error: Division by zero"

// Calculator with history (closure!)
function createCalculator() {
  let history = [];

  return {
    compute(a, b, operation, label) {
      let result = operation(a, b);
      history.push(a + " " + label + " " + b + " = " + result);
      return result;
    },
    getHistory() {
      return history;
    },
    clearHistory() {
      history = [];
      console.log("History cleared.");
    }
  };
}

let calc = createCalculator();
calc.compute(10, 3, add, "+");        // 13
calc.compute(100, 7, subtract, "-");  // 93
calc.compute(6, 7, multiply, "×");    // 42

console.log("\nCalculation History:");
for (let entry of calc.getHistory()) {
  console.log("  " + entry);
}

