console.log(colors.includes("purple")); // false

// indexOf: WHERE is this value? (returns index or -1)
console.log(colors.indexOf("blue"));    // 2
console.log(colors.indexOf("green"));   // 1 (first occurrence)
console.log(colors.indexOf("purple"));  // -1 (not found)

let numbers = [4, 9, 16, 25, 36];

// find: returns the FIRST element that matches
let firstBig = numbers.find(n => n > 15);
console.log(firstBig); // 16

// findIndex: returns the INDEX of the first match
let index = numbers.findIndex(n => n > 15);
console.log(index); // 2

// No match? find returns undefined, findIndex returns -1
console.log(numbers.find(n => n > 100));      // undefined
console.log(numbers.findIndex(n => n > 100)); // -1

let ages = [25, 30, 17, 42, 19];

// some: Does AT LEAST ONE element match?
console.log(ages.some(age => age < 18));  // true (17 is < 18)
console.log(ages.some(age => age > 50));  // false (none > 50)

// every: Do ALL elements match?
console.log(ages.every(age => age > 0));   // true (all positive)
console.log(ages.every(age => age >= 18)); // false (17 fails)

