};

// Method 1: 'in' operator (checks if key exists)
console.log("name" in user);     // true
console.log("phone" in user);    // false
console.log("email" in user);    // true (exists, even though value is undefined)

// Method 2: hasOwnProperty()
console.log(user.hasOwnProperty("name"));   // true
console.log(user.hasOwnProperty("phone"));  // false

// Method 3: Checking against undefined (careful!)
console.log(user.phone !== undefined);  // false (doesn't exist)
