sections.code:
const studentDB = {
  students: [],

  addStudent(name, age, grades = {}) {
    const id = this.students.length + 1;
    this.students.push({ id, name, age, grades, enrolledDate: new Date().toISOString().split('T')[0] });
    console.log(`✅ Added: ${name} (ID: ${id})`);
  },

  findStudent(name) {
    return this.students.find(s => s.name.toLowerCase() === name.toLowerCase());
  },

  updateGrade(name, subject, grade) {
    const student = this.findStudent(name);
    if (!student) {
      console.log(`❌ Student "${name}" not found`);
      return;
    }
    student.grades[subject] = grade;
    console.log(`📝 ${name}'s ${subject} grade updated to ${grade}`);
  },

  getAverage(name) {
    const student = this.findStudent(name);
    if (!student) return null;
    const gradeValues = Object.values(student.grades);
    if (gradeValues.length === 0) return 0;
    return gradeValues.reduce((sum, g) => sum + g, 0) / gradeValues.length;
  },

  getHonorRoll() {
    return this.students
      .filter(s => this.getAverage(s.name) >= 90)
      .map(s => ({ ...s, average: this.getAverage(s.name) }));
  },

  printReport() {
    console.log("\n📊 STUDENT REPORT");
    console.log("═".repeat(40));
    for (const { name, age, grades } of this.students) {
      const avg = this.getAverage(name);
      console.log(`${name} (Age: ${age}) — Avg: ${avg.toFixed(1)}`);
      for (const [subject, grade] of Object.entries(grades)) {
        console.log(`  📘 ${subject}: ${grade}`);
      }
    }
  }
};

// Test it!
studentDB.addStudent("Alice", 20, { math: 95, science: 88, english: 92 });
studentDB.addStudent("Bob", 22, { math: 78, science: 82, english: 85 });
studentDB.addStudent("Charlie", 21, { math: 91, science: 94, english: 96 });

studentDB.updateGrade("Bob", "history", 90);
studentDB.printReport();

console.log("\n🏆 Honor Roll:", studentDB.getHonorRoll().map(s => s.name));

