// getElementsByClassName — returns an HTMLCollection
const cards = document.getElementsByClassName("card");
console.log(cards);        // HTMLCollection(2) [section.card, section.card]
console.log(cards.length); // 2
console.log(cards[0]);     // First .card element

// getElementsByTagName — returns an HTMLCollection
const allH2s = document.getElementsByTagName("h2");
console.log(allH2s);        // HTMLCollection(2) [h2, h2]
console.log(allH2s.length); // 2

// ⚠️ KEY DIFFERENCE: HTMLCollection is LIVE!
// If you add/remove elements, the collection updates automatically.
// NodeList from querySelectorAll is STATIC — it's a snapshot.

// ⚠️ HTMLCollection does NOT have .forEach()!
// You need to convert it first:
Array.from(cards).forEach(card => {
  console.log(card);
});

// 🏆 BEST PRACTICE: Store selected elements in well-named variables

// Use const — the variable shouldn't be reassigned
const header = document.getElementById("main-header");
const navLinks = document.querySelectorAll(".nav-link");
const firstCard = document.querySelector(".card");
const footer = document.querySelector("#main-footer");

// Naming convention: many developers prefix with $ or use El suffix
const $header = document.querySelector("#main-header");
const headerEl = document.getElementById("main-header");

// Now you can work with these elements:
console.log(header.id);           // "main-header"
console.log(header.tagName);      // "HEADER" (always uppercase)
console.log(header.className);    // class name(s) as a string
console.log(navLinks.length);     // 3

// ⚠️ ALWAYS check if element exists before using it!
const maybeElement = document.querySelector(".might-not-exist");
if (maybeElement) {
  console.log("Found it!", maybeElement);
} else {
  console.log("Element not found");
}

