const example = document.getElementById("example");

// textContent gets EVERYTHING — including hidden text
console.log(example.textContent);
// "\n  Visible text\n  Hidden text\n     Extra   spaces   \n"
// Includes hidden text, preserves whitespace

// innerText only gets VISIBLE text, normalized spacing
console.log(example.innerText);
// "Visible text\nExtra spaces"
// Hidden text is excluded! Whitespace is collapsed.

// ✅ Use textContent (faster, simpler, more predictable)
// 🤷 Use innerText only when you care about visual presentation

