// These are the final computed values after all CSS rules,
// inheritance, and browser defaults have been applied.

// ⚠️ getComputedStyle is READ-ONLY — you can't set styles with it
// styles.color = "blue"; // This won't work!

/* Define styles as classes */
.hidden { display: none; }
.visible { display: block; }
.highlight { background-color: yellow; font-weight: bold; }
.error { color: red; border: 2px solid red; }
.success { color: green; border: 2px solid green; }
.dark-mode { background-color: #1a1a2e; color: #eee; }
.rounded { border-radius: 50%; }
.large-text { font-size: 2rem; }
.shake { animation: shake 0.5s; }

const box = document.querySelector(".box");

