box.classList.remove("rounded", "large-text");

// 🔄 TOGGLE — add if missing, remove if present
box.classList.toggle("hidden");
// If box had "hidden" → removes it (now visible)
// If box didn't have "hidden" → adds it (now hidden)

// toggle returns true (was added) or false (was removed)
const wasAdded = box.classList.toggle("active");
console.log(wasAdded); // true if "active" was added, false if removed

