// Create a new <p> element
const newParagraph = document.createElement("p");
// At this point, newParagraph exists in memory
// but is NOT visible on the page — it's "floating" in JS land

console.log(newParagraph); // <p></p>  (empty element)

// Create other types of elements
const newDiv = document.createElement("div");
const newButton = document.createElement("button");
const newImg = document.createElement("img");
const newInput = document.createElement("input");
const newLi = document.createElement("li");
const newA = document.createElement("a");

// Create and configure a paragraph
const newParagraph = document.createElement("p");
newParagraph.textContent = "This paragraph was created by JavaScript!";
newParagraph.classList.add("dynamic-text", "highlight");
newParagraph.id = "new-para";

// Create and configure a link
const newLink = document.createElement("a");
newLink.textContent = "Visit Google";
newLink.href = "https://www.google.com";
newLink.target = "_blank";
newLink.classList.add("external-link");

// Create and configure an image
const newImg = document.createElement("img");
newImg.src = "photo.jpg";
newImg.alt = "A beautiful photo";
newImg.classList.add("gallery-image");

// Create and configure a button
const newButton = document.createElement("button");
newButton.textContent = "Click Me!";
newButton.type = "button";
newButton.classList.add("btn", "btn-primary");

// Create a list item with nested content
const newLi = document.createElement("li");
newLi.textContent = "New list item";

// None of these are on the page yet! We need Step 3...

// HTML: <div id="container">
//         <p>Existing paragraph 1</p>
//         <p>Existing paragraph 2</p>
//       </div>

const container = document.getElementById("container");

// ====== append() — Add as LAST child ======
const newP = document.createElement("p");
newP.textContent = "I'm appended (at the end)";
container.append(newP);
// Result:
// <div id="container">
//   <p>Existing paragraph 1</p>
//   <p>Existing paragraph 2</p>
//   <p>I'm appended (at the end)</p>     ← NEW, at the end
// </div>

// ====== prepend() — Add as FIRST child ======
const firstP = document.createElement("p");
firstP.textContent = "I'm prepended (at the start)";
container.prepend(firstP);
// Result:
// <div id="container">
//   <p>I'm prepended (at the start)</p>  ← NEW, at the start
//   <p>Existing paragraph 1</p>
//   <p>Existing paragraph 2</p>
//   <p>I'm appended (at the end)</p>
// </div>

// ====== before() — Add BEFORE a specific element ======
const existingP = document.querySelector("#container p:nth-child(2)");
const beforeP = document.createElement("p");
beforeP.textContent = "I'm inserted BEFORE paragraph 1";
existingP.before(beforeP);

// ====== after() — Add AFTER a specific element ======
const afterP = document.createElement("p");
afterP.textContent = "I'm inserted AFTER paragraph 1";
existingP.after(afterP);

// ====== append can also add plain text! ======
container.append("Just some text at the end");

// THE PATTERN YOU'LL USE CONSTANTLY:

// Step 1: Create
const card = document.createElement("div");

// Step 2: Configure
card.classList.add("card");
card.innerHTML = `
  <h3>New Product</h3>
  <p class="price">$24.99</p>
  <button class="buy-btn">Buy Now</button>
`;

// Step 3: Attach
document.querySelector(".products-grid").append(card);

// ✅ Done! The card is now visible on the page.


// ANOTHER EXAMPLE: Adding a to-do item
function addTodo(text) {
  // 1. Create
  const li = document.createElement("li");

  // 2. Configure
  li.textContent = text;
  li.classList.add("todo-item");

  // 3. Attach
  document.getElementById("todo-list").append(li);
}

addTodo("Buy groceries");
addTodo("Walk the dog");
addTodo("Learn JavaScript");

// ====== Method 1: element.remove() — Modern, simple ======
const para = document.querySelector(".old-paragraph");
para.remove(); // Gone from the page! 💨

// ====== Method 2: parent.removeChild(child) — Older method ======
const list = document.getElementById("my-list");
const firstItem = list.querySelector("li");
list.removeChild(firstItem);

// ====== Practical: Remove with a condition ======
const items = document.querySelectorAll(".item");
items.forEach(item => {
  if (item.textContent.includes("DELETE ME")) {
    item.remove();
  }
});

// ====== Remove ALL children of an element ======
const container = document.getElementById("container");

// Method A: Set innerHTML to empty (quick but destroys event listeners)
container.innerHTML = "";

// Method B: Loop and remove (preserves reference safety)
while (container.firstChild) {
  container.removeChild(container.firstChild);
}

// Method C: replaceChildren with nothing (modern)
container.replaceChildren(); // Removes all children!

// ====== Replace an element ======
const oldElement = document.querySelector(".old");
const newElement = document.createElement("div");
newElement.textContent = "I'm the replacement!";
oldElement.replaceWith(newElement);

// Sometimes createElement is overkill for simple additions.
// insertAdjacentHTML lets you insert HTML strings at specific positions.

const container = document.getElementById("container");

// 4 positions: 'beforebegin', 'afterbegin', 'beforeend', 'afterend'

// Insert HTML before the opening tag (as a sibling before)
container.insertAdjacentHTML("beforebegin", "<p>Before container</p>");

// Insert HTML right after the opening tag (as first child)
container.insertAdjacentHTML("afterbegin", "<p>First inside container</p>");

// Insert HTML right before the closing tag (as last child)
container.insertAdjacentHTML("beforeend", "<p>Last inside container</p>");

// Insert HTML after the closing tag (as a sibling after)
container.insertAdjacentHTML("afterend", "<p>After container</p>");

// WHY use this?
// 1. Faster than innerHTML += (doesn't destroy existing elements)
// 2. Simpler than createElement for quick additions
// 3. Preserves event listeners on existing elements

// ⚠️ Same XSS warning as innerHTML — don't use with user input!

// When adding MANY elements, adding them one by one causes
// the browser to re-render after each append. This is slow.

// ❌ SLOW — 100 repaints
for (let i = 0; i < 100; i++) {
  const li = document.createElement("li");
  li.textContent = `Item ${i + 1}`;
  document.getElementById("list").append(li); // Repaint each time!
}

// ✅ FAST — 1 repaint with DocumentFragment
const fragment = document.createDocumentFragment();

for (let i = 0; i < 100; i++) {
  const li = document.createElement("li");
  li.textContent = `Item ${i + 1}`;
  fragment.append(li); // No repaint — fragment is invisible
}

// One single append — one single repaint
document.getElementById("list").append(fragment);

// The fragment itself disappears; only its children are added.
// This is the same as appending 100 <li> elements at once.

