// SUPER USEFUL for event delegation (you'll learn in Module 11):
// When a click happens deep in the DOM, use closest() to find
// which parent container was clicked.

// Example: Click on a button inside a card
// buttonInsideCard.closest('.card') → the card that contains the button

// HTML:
// <nav>
//   <a href="/" class="nav-link active">Home</a>
//   <a href="/about" class="nav-link">About</a>
//   <a href="/contact" class="nav-link">Contact</a>
// </nav>

function setActiveLink(clickedLink) {
  // 1. Find the parent nav
  const nav = clickedLink.closest("nav");

  // 2. Remove 'active' from all links in this nav
  nav.querySelectorAll(".nav-link").forEach(link => {
    link.classList.remove("active");
  });

  // 3. Add 'active' to the clicked link
  clickedLink.classList.add("active");
}

// This pattern uses traversal (closest) + selection (querySelectorAll)
// to navigate the DOM relative to the clicked element.

// Another pattern: find a sibling's content
const activeUser = document.querySelector(".user.active");
const nextUser = activeUser.nextElementSibling;
if (nextUser) {
  console.log(`Next user after ${activeUser.textContent} is ${nextUser.textContent}`);
  // "Next user after Bob is Charlie"
}

