// HTML: <div id="user" data-user-id="123" data-role="admin" data-last-login="2025-01-15">

const userCard = document.getElementById("user");

// The .dataset property gives you a DOMStringMap of ALL data attributes
console.log(userCard.dataset);
// DOMStringMap { userId: '123', role: 'admin', lastLogin: '2025-01-15' }

// ⚠️ NOTICE: Hyphenated names become camelCase!
// data-user-id    →  dataset.userId
// data-role       →  dataset.role  
// data-last-login →  dataset.lastLogin

// READING data attributes
console.log(userCard.dataset.userId);    // "123" (string)
console.log(userCard.dataset.role);      // "admin"
console.log(userCard.dataset.lastLogin); // "2025-01-15"

// SETTING data attributes
userCard.dataset.role = "moderator";
// HTML now: data-role="moderator"

userCard.dataset.verified = "true";
// HTML now has: data-verified="true" (new attribute added!)

// DELETING data attributes
delete userCard.dataset.lastLogin;
// data-last-login is removed from the HTML

// Remember: values are always STRINGS
const price = document.querySelector('[data-price]');
console.log(typeof price.dataset.price); // "string"
console.log(Number(price.dataset.price)); // 29.99 (convert to number!)
console.log(price.dataset.price === "29.99"); // true (string comparison)

// HTML:
// <div class="filters">
//   <button data-filter="all">All</button>
//   <button data-filter="electronics">Electronics</button>
//   <button data-filter="accessories">Accessories</button>
// </div>
// <ul id="product-list">
//   <li data-category="electronics" data-price="29.99">Headphones</li>
//   <li data-category="electronics" data-price="49.99">Speaker</li>
//   <li data-category="accessories" data-price="9.99">USB Cable</li>
// </ul>

const filterButtons = document.querySelectorAll("[data-filter]");
const products = document.querySelectorAll("#product-list li");

filterButtons.forEach(button => {
  button.addEventListener("click", function() {
    const filter = this.dataset.filter; // Read which filter was clicked

    products.forEach(product => {
      if (filter === "all" || product.dataset.category === filter) {
        product.style.display = "";      // Show
      } else {
        product.style.display = "none";  // Hide
      }
    });
  });
});

// Calculate total price of visible products
function getTotalPrice() {
  let total = 0;
  products.forEach(product => {
    if (product.style.display !== "none") {
      total += Number(product.dataset.price);
    }
  });
  return total.toFixed(2);
}

console.log("Total:", getTotalPrice()); // "Total: 89.97"

