sections.code:
// ====== SELECT ALL ELEMENTS WE NEED ======
const todoInput = document.getElementById("todo-input");
const addBtn = document.getElementById("add-btn");
const todoList = document.getElementById("todo-list");
const taskCount = document.getElementById("task-count");
const clearCompletedBtn = document.getElementById("clear-completed");

// We'll use a simple counter to generate unique IDs for each task
let taskIdCounter = 0;

function addTask(text) {
  // Don't add empty tasks
  if (text.trim() === "") return;

  // Generate a unique ID
  taskIdCounter++;

  // 1. CREATE the list item
  const li = document.createElement("li");
  li.classList.add("todo-item");
  li.dataset.taskId = taskIdCounter;  // Store ID as data attribute

  // 2. CREATE the text span (clickable to toggle complete)
  const textSpan = document.createElement("span");
  textSpan.classList.add("todo-text");
  textSpan.textContent = text;

  // 3. CREATE the delete button
  const deleteBtn = document.createElement("button");
  deleteBtn.classList.add("delete-btn");
  deleteBtn.textContent = "✕";
  deleteBtn.title = "Delete task";  // Tooltip on hover

  // 4. ASSEMBLE — add text and button to the list item
  li.append(textSpan, deleteBtn);

  // 5. ATTACH — add the list item to the list
  todoList.append(li);

  // 6. UPDATE the task counter
  updateTaskCount();

  console.log(`✅ Task added: "${text}" (ID: ${taskIdCounter})`);
}

// Generated HTML structure for each task:
// <li class="todo-item" data-task-id="1">
//   <span class="todo-text">Buy groceries</span>
//   <button class="delete-btn">✕</button>
// </li>

// TOGGLE a task between complete and incomplete
function toggleTask(taskElement) {
  // Simply toggle the 'completed' class
  taskElement.classList.toggle("completed");

  // Update the task counter (completed tasks don't count)
  updateTaskCount();

  const isCompleted = taskElement.classList.contains("completed");
  const text = taskElement.querySelector(".todo-text").textContent;
  console.log(`${isCompleted ? '☑️' : '☐'} "${text}"`);
}

// DELETE a task
function deleteTask(taskElement) {
  const text = taskElement.querySelector(".todo-text").textContent;

  // Remove from the DOM
  taskElement.remove();

  // Update the task counter
  updateTaskCount();

  console.log(`🗑️ Deleted: "${text}"`);
}

// UPDATE the remaining task count
function updateTaskCount() {
  // Count tasks that are NOT completed
  const allTasks = todoList.querySelectorAll(".todo-item");
  const incompleteTasks = todoList.querySelectorAll(".todo-item:not(.completed)");

  const count = incompleteTasks.length;
  taskCount.textContent = `${count} task${count !== 1 ? 's' : ''} remaining`;
  // "1 task remaining" or "3 tasks remaining"
}

// ====== ADD BUTTON CLICK ======
addBtn.addEventListener("click", function() {
  addTask(todoInput.value);
  todoInput.value = "";    // Clear the input
  todoInput.focus();       // Put cursor back in input
});

// ====== ENTER KEY IN INPUT ======
todoInput.addEventListener("keypress", function(event) {
  if (event.key === "Enter") {
    addTask(todoInput.value);
    todoInput.value = "";
    todoInput.focus();
  }
});

// ====== CLICK ON TODO LIST (Event Delegation) ======
// Instead of adding listeners to each item, we listen on the parent!
todoList.addEventListener("click", function(event) {
  const target = event.target;  // What was actually clicked?

  // Did they click the text? → Toggle complete
  if (target.classList.contains("todo-text")) {
    const todoItem = target.closest(".todo-item"); // Navigate UP to the <li>
    toggleTask(todoItem);
  }

  // Did they click the delete button? → Delete
  if (target.classList.contains("delete-btn")) {
    const todoItem = target.closest(".todo-item"); // Navigate UP to the <li>
    deleteTask(todoItem);
  }
});

// ====== CLEAR COMPLETED BUTTON ======
clearCompletedBtn.addEventListener("click", function() {
  const completedTasks = todoList.querySelectorAll(".todo-item.completed");
  completedTasks.forEach(task => task.remove());
  updateTaskCount();
  console.log(`🧹 Cleared ${completedTasks.length} completed task(s)`);
});

sections.content:
When elements are created dynamically, you can't add event listeners to them before they exist. The solution is **event delegation**:

1. Add ONE listener to a **parent** element that exists from the start
2. When a click happens, check `event.target` to see WHAT was clicked
3. Use `target.closest('.class')` to navigate up to the relevant container

```javascript
// Instead of: (won't work for dynamic elements)
eachButton.addEventListener('click', handleClick);

// Do this: (works for all current AND future elements)
parentContainer.addEventListener('click', function(e) {
  const button = e.target.closest('.my-button');
  if (button) handleClick(button);
});
```

We'll explore this in depth in Module 11: Events.

