// ====== DOM ELEMENTS ======
const todoInput = document.getElementById("todo-input");
const addBtn = document.getElementById("add-btn");
const todoList = document.getElementById("todo-list");
const taskCount = document.getElementById("task-count");
const clearCompletedBtn = document.getElementById("clear-completed");

let taskIdCounter = 0;

// ====== FUNCTIONS ======
function addTask(text) {
  if (text.trim() === "") return;
  taskIdCounter++;

  const li = document.createElement("li");
  li.classList.add("todo-item");
  li.dataset.taskId = taskIdCounter;

  const textSpan = document.createElement("span");
  textSpan.classList.add("todo-text");
  textSpan.textContent = text;

  const deleteBtn = document.createElement("button");
  deleteBtn.classList.add("delete-btn");
  deleteBtn.textContent = "✕";

  li.append(textSpan, deleteBtn);
  todoList.append(li);
  updateTaskCount();
}

function toggleTask(taskEl) {
  taskEl.classList.toggle("completed");
  updateTaskCount();
}

function deleteTask(taskEl) {
  taskEl.remove();
  updateTaskCount();
}

function updateTaskCount() {
  const count = todoList.querySelectorAll(".todo-item:not(.completed)").length;
  taskCount.textContent = `${count} task${count !== 1 ? 's' : ''} remaining`;
}

// ====== EVENT LISTENERS ======
addBtn.addEventListener("click", () => {
  addTask(todoInput.value);
  todoInput.value = "";
  todoInput.focus();
});

todoInput.addEventListener("keypress", (e) => {
  if (e.key === "Enter") {
    addTask(todoInput.value);
    todoInput.value = "";
  }
});

todoList.addEventListener("click", (e) => {
  if (e.target.classList.contains("todo-text")) {
    toggleTask(e.target.closest(".todo-item"));
  }
  if (e.target.classList.contains("delete-btn")) {
    deleteTask(e.target.closest(".todo-item"));
  }
});

clearCompletedBtn.addEventListener("click", () => {
  todoList.querySelectorAll(".completed").forEach(el => el.remove());
  updateTaskCount();
});

// ====== INITIAL STATE ======
updateTaskCount();

