// HTML: <button id="greet-btn">Click Me!</button>
//       <p id="output"></p>

const button = document.querySelector('#greet-btn');
const output = document.querySelector('#output');

// addEventListener(eventType, callbackFunction)
button.addEventListener('click', function() {
  output.textContent = 'Hello! You clicked the button! 🎉';
});

// With an arrow function (more common in modern JS)
button.addEventListener('click', () => {
  output.textContent = 'Hello! You clicked the button! 🎉';
});

// Or define the function separately (best for reuse & removal)
function handleClick() {
  output.textContent = 'Hello! You clicked the button! 🎉';
}
button.addEventListener('click', handleClick);

// ⚠️ CRITICAL: No parentheses after handleClick!
// handleClick   → pass the function itself (CORRECT ✅)
// handleClick() → call it NOW and pass its return value (WRONG ❌)

// Let's count clicks!
let clickCount = 0;
button.addEventListener('click', () => {
  clickCount++;
  output.textContent = `Clicked ${clickCount} time${clickCount === 1 ? '' : 's'}!`;
});

const box = document.querySelector('#color-box');

// An element can have MULTIPLE listeners for the SAME event!
box.addEventListener('click', () => {
  console.log('Listener 1: Box was clicked!');
});

box.addEventListener('click', () => {
  console.log('Listener 2: Also heard the click!');
});
// BOTH run when the box is clicked!

// Different events on the same element
box.addEventListener('mouseenter', () => {
  box.style.backgroundColor = 'lightblue';
  box.textContent = 'Mouse is here! 🐭';
});

box.addEventListener('mouseleave', () => {
  box.style.backgroundColor = 'lightgray';
  box.textContent = 'Hover over me!';
});

box.addEventListener('click', () => {
  box.classList.toggle('active');
});

const button = document.querySelector('#one-time-btn');

// To remove a listener, you need the EXACT same function reference
function handleOneClick() {
  console.log('This only happens once!');
  button.removeEventListener('click', handleOneClick); // Remove itself!
  button.textContent = 'Already Clicked';
  button.disabled = true;
}

button.addEventListener('click', handleOneClick);

// ⚠️ This WON'T work — two different function objects:
button.addEventListener('click', () => console.log('A'));
button.removeEventListener('click', () => console.log('A'));
// ☝️ These LOOK identical but are two separate functions in memory!

// ✅ Modern alternative: { once: true }
button.addEventListener('click', () => {
  console.log('This fires exactly once, then auto-removes!');
}, { once: true });

// ✅ Another pattern: AbortController (for removing multiple listeners at once)
const controller = new AbortController();

button.addEventListener('click', () => console.log('Click!'), 
  { signal: controller.signal });
button.addEventListener('mouseenter', () => console.log('Hover!'), 
  { signal: controller.signal });

// Remove ALL listeners tied to this controller:
controller.abort(); // Both listeners are gone!

