// HTML:
// <div id="color-palette">
//   <div class="color" style="background:red" data-color="red"></div>
//   <div class="color" style="background:blue" data-color="blue"></div>
//   <div class="color" style="background:green" data-color="green"></div>
//   <div class="color" style="background:purple" data-color="purple"></div>
// </div>
// <div id="preview" style="width:200px;height:200px;border:1px solid #ccc"></div>

const palette = document.querySelector('#color-palette');
const preview = document.querySelector('#preview');

// ONE listener on the parent handles ALL color swatches!
palette.addEventListener('click', (e) => {
  // Check if the clicked element is actually a color swatch
  if (e.target.classList.contains('color')) {
    const selectedColor = e.target.dataset.color;
    preview.style.backgroundColor = selectedColor;
    preview.textContent = `Selected: ${selectedColor}`;

    // Highlight the selected swatch
    document.querySelectorAll('.color').forEach(c => c.classList.remove('selected'));
    e.target.classList.add('selected');
  }
});

// This is MUCH better than adding a listener to each color div!
// And it works even if you add new colors later!

// The browser has DEFAULT behaviors for some events:
// - Clicking a link → navigates to the URL
// - Submitting a form → reloads the page
// - Right-clicking → shows context menu
// - Pressing Enter in a form → submits it

// preventDefault() STOPS these default behaviors!

// Example 1: Prevent form from reloading the page
const form = document.querySelector('#login-form');

form.addEventListener('submit', (e) => {
  e.preventDefault(); // ⛔ Stop the page refresh!

  const email = document.querySelector('#email').value;
  const password = document.querySelector('#password').value;

  console.log('Form data:', { email, password });
  // Now handle the form with JavaScript instead!
  // Later you'll send this to a server with fetch()
});

// Example 2: Prevent link from navigating
const stayLink = document.querySelector('#stay-here');
stayLink.addEventListener('click', (e) => {
  e.preventDefault(); // ⛔ Don't navigate!
  console.log('Link clicked but page stays put!');
  // Maybe show a modal or load content dynamically
});

// Example 3: Prevent only certain keys in an input
const numberInput = document.querySelector('#numbers-only');
numberInput.addEventListener('keydown', (e) => {
  // Allow: digits, backspace, delete, arrows, tab
  const allowed = ['Backspace', 'Delete', 'Tab', 'ArrowLeft', 'ArrowRight'];
  if (!allowed.includes(e.key) && !/^\d$/.test(e.key)) {
    e.preventDefault(); // Block non-numeric characters
  }
});

// Example 4: Confirm before leaving page
// window.addEventListener('beforeunload', (e) => {
//   e.preventDefault();  // Modern browsers show a confirmation dialog
//   e.returnValue = '';  // Required for some browsers
// });

// HTML:
// <div id="outer" style="padding:20px; background:#eee">
//   <button id="inner">Click Me</button>
// </div>

const outer = document.querySelector('#outer');

outer.addEventListener('click', (e) => {
  console.log('target:', e.target);        // What was ACTUALLY clicked
  console.log('currentTarget:', e.currentTarget); // Where the LISTENER is

  // If you click the BUTTON:
  // target: <button id="inner">       ← The actual clicked element
  // currentTarget: <div id="outer">   ← The element with the listener

  // If you click the DIV background:
  // target: <div id="outer">          ← Same as currentTarget
  // currentTarget: <div id="outer">   ← Same element
});

// Summary:
// event.target       = The element that ORIGINATED the event
// event.currentTarget = The element the LISTENER is attached to
// They're the same when you click the exact element with the listener.
// They differ when you click a child — the event bubbles up.

// Inside the callback, 'this' === event.currentTarget
// (But NOT with arrow functions! Arrow functions don't bind 'this')

