const canvas = document.querySelector('#drawing-area');

// === MOUSE COORDINATE SYSTEMS ===
canvas.addEventListener('mousemove', (e) => {
  // Different coordinate systems — each useful for different things:

  // clientX/Y: Relative to the VIEWPORT (browser window)
  console.log(`Viewport: ${e.clientX}, ${e.clientY}`);

  // pageX/Y: Relative to the ENTIRE PAGE (includes scroll offset)
  console.log(`Page: ${e.pageX}, ${e.pageY}`);

  // offsetX/Y: Relative to the TARGET ELEMENT's top-left corner
  console.log(`Element: ${e.offsetX}, ${e.offsetY}`);
  // ☝️ Best for drawing apps, games, and element-relative positioning
});

// === MOUSE BUTTONS ===
canvas.addEventListener('mousedown', (e) => {
  // e.button tells you which button was pressed:
  // 0 = Left (primary)
  // 1 = Middle (scroll wheel)
  // 2 = Right (secondary)
  console.log(`Button: ${e.button}`);

  if (e.button === 0) console.log('Left click');
  if (e.button === 2) console.log('Right click');
});

// === CLICK VARIANTS ===
canvas.addEventListener('click', () => console.log('Single click'));
canvas.addEventListener('dblclick', () => console.log('Double click'));

// Prevent right-click context menu (use sparingly!)
canvas.addEventListener('contextmenu', (e) => {
  e.preventDefault();
  console.log('Custom right-click action!');
});

// === KEY EVENTS ===
document.addEventListener('keydown', (e) => {
  // e.key — the LOGICAL key that was pressed
  console.log(`Key: ${e.key}`);      // 'a', 'Enter', 'Shift', 'ArrowUp'

  // e.code — the PHYSICAL key on the keyboard
  console.log(`Code: ${e.code}`);    // 'KeyA', 'Enter', 'ShiftLeft', 'ArrowUp'
  // Use e.key for most situations
  // Use e.code when physical position matters (game controls: WASD)

  // Modifier keys
  console.log(`Shift: ${e.shiftKey}`);
  console.log(`Ctrl:  ${e.ctrlKey}`);
  console.log(`Alt:   ${e.altKey}`);
  console.log(`Meta:  ${e.metaKey}`); // Cmd on Mac, Win on Windows
});

// === COMMON PATTERN: Enter key in an input ===
const searchInput = document.querySelector('#search');
searchInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') {
    const query = searchInput.value.trim();
    if (query) {
      console.log(`Searching for: ${query}`);
      // performSearch(query);
    }
  }
});

// === COMMON PATTERN: Escape key to close things ===
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') {
    // Close modals, dropdowns, popups, etc.
    const modal = document.querySelector('.modal:not(.hidden)');
    if (modal) modal.classList.add('hidden');
  }
});

// === Keyboard Shortcuts System ===
const shortcuts = {
  'ctrl+s': () => { console.log('💾 Save!'); },
  'ctrl+z': () => { console.log('↩️ Undo!'); },
  'ctrl+shift+z': () => { console.log('↪️ Redo!'); },
};

document.addEventListener('keydown', (e) => {
  let combo = '';
  if (e.ctrlKey || e.metaKey) combo += 'ctrl+';
  if (e.shiftKey) combo += 'shift+';
  if (e.altKey) combo += 'alt+';
  combo += e.key.toLowerCase();

  if (shortcuts[combo]) {
    e.preventDefault(); // Stop browser's default (e.g., Ctrl+S save dialog)
    shortcuts[combo]();
  }
});

const canvas = document.querySelector('#draw-canvas');
let isDrawing = false;
let lastX = 0;
let lastY = 0;

// Start drawing on mousedown
canvas.addEventListener('mousedown', (e) => {
  isDrawing = true;
  lastX = e.offsetX;
  lastY = e.offsetY;
});

// Draw on mousemove (only while mouse button is held)
canvas.addEventListener('mousemove', (e) => {
  if (!isDrawing) return;

  // Create a line element from last position to current position
  const line = document.createElement('div');
  line.classList.add('draw-dot');
  line.style.cssText = `
    position: absolute;
    width: 4px;
    height: 4px;
    background: black;
    border-radius: 50%;
    left: ${e.offsetX}px;
    top: ${e.offsetY}px;
    pointer-events: none;
  `;
  canvas.appendChild(line);

  lastX = e.offsetX;
  lastY = e.offsetY;
});

// Stop drawing on mouseup or mouseleave
canvas.addEventListener('mouseup', () => { isDrawing = false; });
canvas.addEventListener('mouseleave', () => { isDrawing = false; });

// Clear canvas
document.querySelector('#clear-btn').addEventListener('click', () => {
  canvas.querySelectorAll('.draw-dot').forEach(dot => dot.remove());
});

// This pattern — tracking state (isDrawing) across multiple
// events — is used everywhere: drag-and-drop, selection boxes,
// slider controls, resizable panels, etc.

