// HTML:
// <div id="grandparent" style="padding:30px; background:#f0f0f0">
//   GRANDPARENT
//   <div id="parent" style="padding:30px; background:#d0d0d0">
//     PARENT
//     <button id="child">CHILD BUTTON</button>
//   </div>
// </div>

document.querySelector('#grandparent').addEventListener('click', () => {
  console.log('3. 👴 Grandparent heard the click!');
});

document.querySelector('#parent').addEventListener('click', () => {
  console.log('2. 👨 Parent heard the click!');
});

document.querySelector('#child').addEventListener('click', () => {
  console.log('1. 👶 Child (button) was clicked!');
});

// When you click the BUTTON, ALL THREE fire! Output:
// "1. 👶 Child (button) was clicked!"
// "2. 👨 Parent heard the click!"
// "3. 👴 Grandparent heard the click!"

// The event started at the child and BUBBLED UP!
// If you click the PARENT div directly:
// "2. 👨 Parent heard the click!"
// "3. 👴 Grandparent heard the click!"
// (Child does NOT fire — the event started at the parent)

// Sometimes you DON'T want the event to bubble up

// Scenario: A delete button inside a card.
// Clicking delete should delete, NOT also trigger the card's click handler.

const card = document.querySelector('.card');
const deleteBtn = card.querySelector('.delete-btn');

// Card click → open detail view
card.addEventListener('click', () => {
  console.log('Opening card detail...');
  // navigateToDetail(card.dataset.id);
});

// Delete click → delete the card (should NOT open detail!)
deleteBtn.addEventListener('click', (e) => {
  e.stopPropagation(); // ⛔ Stop bubbling! Card's listener won't fire.
  console.log('Deleting card...');
  card.remove();
});

// Without stopPropagation, clicking delete would:
// 1. Delete the card ✅
// 2. ALSO try to open the detail view ❌ (from bubbling)

// ⚠️ Use stopPropagation sparingly!
// It can break event delegation and make debugging harder.
// Often there's a better solution (checking e.target in the parent handler).

// HTML:
// <ul id="todo-list">
//   <li data-id="1">Buy groceries <button class="delete">✕</button></li>
//   <li data-id="2">Walk the dog <button class="delete">✕</button></li>
//   <li data-id="3">Read a book <button class="delete">✕</button></li>
// </ul>

// ❌ BAD: Adding a listener to EACH delete button
const buttons = document.querySelectorAll('.delete');
buttons.forEach(btn => {
  btn.addEventListener('click', (e) => {
    e.target.closest('li').remove();
  });
});
// Problem 1: If you add new items later, they WON'T have listeners!
// Problem 2: 100 items = 100 listeners = more memory


// ✅ GOOD: ONE listener on the parent using event delegation
const todoList = document.querySelector('#todo-list');

todoList.addEventListener('click', (e) => {
  // Was a delete button clicked?
  const deleteBtn = e.target.closest('.delete');
  if (deleteBtn) {
    const listItem = deleteBtn.closest('li');
    const itemId = listItem.dataset.id;
    console.log(`Deleting item #${itemId}`);
    listItem.remove();
    return;
  }

  // Was a list item itself clicked? (toggle complete)
  const listItem = e.target.closest('li');
  if (listItem) {
    listItem.classList.toggle('completed');
  }
});

// Now add a new item — it AUTOMATICALLY works!
const newItem = document.createElement('li');
newItem.dataset.id = '4';
newItem.innerHTML = 'New task! <button class="delete">✕</button>';
todoList.appendChild(newItem);
// ☝️ This item's delete button ALREADY works — no extra listener needed!

// matches() checks if an element matches a CSS selector
const btn = document.querySelector('button');
console.log(btn.matches('.primary'));     // true if it has class 'primary'
console.log(btn.matches('[disabled]'));   // true if it's disabled
console.log(btn.matches('button.big'));   // true if it's a button with class 'big'

// closest() walks UP the tree to find an ancestor matching a selector
// (We covered this in Module 10, but it's ESSENTIAL for delegation)

// Robust delegation pattern:
const container = document.querySelector('#app');

container.addEventListener('click', (e) => {
  // Pattern: check multiple possible targets

  // Edit button clicked?
  if (e.target.matches('.edit-btn') || e.target.closest('.edit-btn')) {
    const card = e.target.closest('.card');
    if (card) editCard(card.dataset.id);
    return;
  }

  // Delete button clicked?
  if (e.target.matches('.delete-btn') || e.target.closest('.delete-btn')) {
    const card = e.target.closest('.card');
    if (card) deleteCard(card.dataset.id);
    return;
  }

  // Card itself clicked? (but not a button inside it)
  const card = e.target.closest('.card');
  if (card && !e.target.closest('button')) {
    openCard(card.dataset.id);
  }
});

// ☝️ Why check e.target.closest('.edit-btn')?
// Because the button might contain an icon: <button class="edit-btn"><i>✏️</i></button>
// If the user clicks the icon, e.target is the <i>, not the button!
// closest('.edit-btn') finds the button from the icon.

sections.content:
Think about the Twitter timeline. There could be hundreds of tweets on screen, each with like, retweet, and reply buttons. Does Twitter add separate event listeners to every single button? No! That would be thousands of listeners.

Instead, Twitter uses **event delegation**: ONE listener on the entire timeline container. When you click a like button, the event bubbles up to the container. The handler checks event.target to figure out what was clicked and which tweet it belongs to.

```javascript
// Simplified version of what Twitter does:
timeline.addEventListener('click', (e) => {
  const tweetCard = e.target.closest('[data-tweet-id]');
  if (!tweetCard) return;

  const tweetId = tweetCard.dataset.tweetId;

  if (e.target.closest('.like-btn')) likeTweet(tweetId);
  if (e.target.closest('.retweet-btn')) retweetTweet(tweetId);
  if (e.target.closest('.reply-btn')) openReply(tweetId);
});
```

This works for all tweets — even ones loaded later via infinite scroll!

