const passwordInput = document.querySelector('#password');
const strengthBar = document.querySelector('#strength-bar');
const strengthText = document.querySelector('#strength-text');

function getPasswordStrength(password) {
  let score = 0;
  if (password.length >= 8) score++;
  if (password.length >= 12) score++;
  if (/[A-Z]/.test(password)) score++;    // Has uppercase
  if (/[a-z]/.test(password)) score++;    // Has lowercase
  if (/[0-9]/.test(password)) score++;    // Has number
  if (/[^A-Za-z0-9]/.test(password)) score++; // Has special character

  if (score <= 2) return { label: 'Weak', color: '#ef4444', width: '33%' };
  if (score <= 4) return { label: 'Medium', color: '#f59e0b', width: '66%' };
  return { label: 'Strong', color: '#10b981', width: '100%' };
}

passwordInput.addEventListener('input', (e) => {
  const password = e.target.value;

  if (password.length === 0) {
    strengthBar.style.width = '0';
    strengthText.textContent = '';
    return;
  }

  const strength = getPasswordStrength(password);
  strengthBar.style.width = strength.width;
  strengthBar.style.backgroundColor = strength.color;
  strengthBar.style.transition = 'all 0.3s ease';
  strengthText.textContent = `Strength: ${strength.label}`;
  strengthText.style.color = strength.color;
});

