// HTML:
// <button id="open-modal">Open Modal</button>
// <div id="modal-overlay" class="hidden">
//   <div id="modal">
//     <h2>Are you sure?</h2>
//     <p>This action cannot be undone.</p>
//     <div class="modal-buttons">
//       <button id="confirm-btn">Confirm</button>
//       <button id="cancel-btn">Cancel</button>
//     </div>
//   </div>
// </div>

const openBtn = document.querySelector('#open-modal');
const overlay = document.querySelector('#modal-overlay');
const confirmBtn = document.querySelector('#confirm-btn');
const cancelBtn = document.querySelector('#cancel-btn');

function openModal() {
  overlay.classList.remove('hidden');
  document.body.style.overflow = 'hidden'; // Prevent scrolling behind modal
  confirmBtn.focus(); // Accessibility: focus the primary action
}

function closeModal() {
  overlay.classList.add('hidden');
  document.body.style.overflow = ''; // Re-enable scrolling
  openBtn.focus(); // Return focus to the trigger
}

// Open
openBtn.addEventListener('click', openModal);

// Close with Cancel button
cancelBtn.addEventListener('click', closeModal);

// Close by clicking the overlay BACKGROUND (not the modal itself)
overlay.addEventListener('click', (e) => {
  if (e.target === overlay) { // Only if clicking the dark background
    closeModal();
  }
});

// Close with Escape key
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape' && !overlay.classList.contains('hidden')) {
    closeModal();
  }
});

// Confirm action
confirmBtn.addEventListener('click', () => {
  console.log('✅ Action confirmed!');
  closeModal();
});

// HTML:
// <div class="tabs">
//   <div class="tab-buttons">
//     <button class="tab-btn active" data-tab="overview">Overview</button>
//     <button class="tab-btn" data-tab="features">Features</button>
//     <button class="tab-btn" data-tab="pricing">Pricing</button>
//   </div>
//   <div class="tab-content active" id="overview">Overview content here...</div>
//   <div class="tab-content" id="features">Features content here...</div>
//   <div class="tab-content" id="pricing">Pricing content here...</div>
// </div>

const tabContainer = document.querySelector('.tab-buttons');

// Event delegation — ONE listener for all tab buttons
tabContainer.addEventListener('click', (e) => {
  const clickedTab = e.target.closest('.tab-btn');
  if (!clickedTab) return; // Clicked somewhere else

  const targetTabId = clickedTab.dataset.tab;

  // Deactivate all tabs and content panels
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.classList.remove('active');
    btn.setAttribute('aria-selected', 'false');
  });
  document.querySelectorAll('.tab-content').forEach(content => {
    content.classList.remove('active');
  });

  // Activate the clicked tab and its content
  clickedTab.classList.add('active');
  clickedTab.setAttribute('aria-selected', 'true');
  document.querySelector(`#${targetTabId}`).classList.add('active');
});

// Keyboard navigation: arrow keys to switch tabs
tabContainer.addEventListener('keydown', (e) => {
  if (!['ArrowLeft', 'ArrowRight'].includes(e.key)) return;

  const tabs = [...document.querySelectorAll('.tab-btn')];
  const currentIndex = tabs.findIndex(tab => tab.classList.contains('active'));

  let newIndex;
  if (e.key === 'ArrowRight') {
    newIndex = (currentIndex + 1) % tabs.length;
  } else {
    newIndex = (currentIndex - 1 + tabs.length) % tabs.length;
  }

  tabs[newIndex].click();  // Trigger the click handler
  tabs[newIndex].focus();  // Move focus to the new tab
});

// HTML:
// <div class="accordion">
//   <div class="accordion-item">
//     <button class="accordion-header">What is JavaScript? <span class="icon">▶</span></button>
//     <div class="accordion-panel">
//       <p>JavaScript is a programming language...</p>
//     </div>
//   </div>
//   <div class="accordion-item">
//     <button class="accordion-header">Why learn it? <span class="icon">▶</span></button>
//     <div class="accordion-panel">
//       <p>JavaScript is the language of the web...</p>
//     </div>
//   </div>
// </div>

// CSS:
// .accordion-panel { max-height: 0; overflow: hidden; transition: max-height 0.3s ease; }
// .accordion-item.open .accordion-panel { max-height: 500px; }
// .accordion-item.open .icon { transform: rotate(90deg); }

const accordion = document.querySelector('.accordion');

accordion.addEventListener('click', (e) => {
  const header = e.target.closest('.accordion-header');
  if (!header) return;

  const item = header.closest('.accordion-item');
  const isOpen = item.classList.contains('open');

  // Close all items first (for single-open accordion)
  accordion.querySelectorAll('.accordion-item').forEach(i => {
    i.classList.remove('open');
  });

  // Toggle the clicked item (if it was closed, open it)
  if (!isOpen) {
    item.classList.add('open');
  }

  // For multi-open accordion, just toggle:
  // item.classList.toggle('open');
});

// The animation is handled entirely by CSS!
// max-height transitions from 0 to 500px smoothly.
// JavaScript only toggles the 'open' class.

// Quiz questions
const quizData = [
  {
    question: 'What does DOM stand for?',
    options: [
      'Document Object Model',
      'Data Object Manager',
      'Digital Output Machine',
      'Document Order Method'
    ],
    correct: 0,
    explanation: 'DOM stands for Document Object Model — the tree representation of a web page that JavaScript can interact with.'
  },
  {
    question: 'Which method selects the FIRST matching element?',
    options: [
      'querySelectorAll()',
      'getElementsByClassName()',
      'querySelector()',
      'getElementById()'
    ],
    correct: 2,
    explanation: 'querySelector() returns the first element matching a CSS selector. querySelectorAll() returns ALL matches.'
  },
  {
    question: 'What does event.preventDefault() do?',
    options: [
      'Prevents the event from firing',
      'Stops the browser\'s default action for that event',
      'Removes the event listener',
      'Prevents other listeners from running'
    ],
    correct: 1,
    explanation: 'preventDefault() stops the browser\'s built-in behavior — like form submission reloading the page or a link navigating away.'
  },
  {
    question: 'What is event delegation?',
    options: [
      'Adding listeners to every element individually',
      'Removing events from the DOM',
      'Putting one listener on a parent to handle events from its children',
      'Preventing events from bubbling'
    ],
    correct: 2,
    explanation: 'Event delegation uses bubbling — one listener on a parent catches events from all children, even dynamically added ones.'
  },
  {
    question: 'Which property gives the actual element that was clicked?',
    options: [
      'event.currentTarget',
      'event.target',
      'event.source',
      'event.element'
    ],
    correct: 1,
    explanation: 'event.target is the actual element that triggered the event. event.currentTarget is the element the listener is attached to.'
  }
];

// Quiz state
const state = {
  currentQuestion: 0,
  score: 0,
  answers: [],
  timeLeft: 15,
  timerId: null,
  isFinished: false,
};

const quizContainer = document.querySelector('#quiz-container');

function renderQuestion() {
  const q = quizData[state.currentQuestion];
  const questionNum = state.currentQuestion + 1;
  const totalQuestions = quizData.length;

  quizContainer.innerHTML = `
    <div class="quiz-header">
      <div class="progress">
        <div class="progress-bar" style="width: ${(questionNum / totalQuestions) * 100}%"></div>
      </div>
      <div class="quiz-meta">
        <span>Question ${questionNum}/${totalQuestions}</span>
        <span id="timer" class="timer">⏰ ${state.timeLeft}s</span>
      </div>
    </div>

    <div class="question">
      <h2>${q.question}</h2>
    </div>

    <div class="options" id="options">
      ${q.options.map((option, index) => `
        <button class="option-btn" data-index="${index}">
          <span class="option-key">${index + 1}</span>
          ${option}
        </button>
      `).join('')}
    </div>

    <div class="quiz-footer">
      <span class="score-display">Score: ${state.score}/${state.currentQuestion}</span>
    </div>
  `;

  startTimer();
}

function startTimer() {
  state.timeLeft = 15;
  updateTimerDisplay();

  // Clear any existing timer
  if (state.timerId) clearInterval(state.timerId);

  state.timerId = setInterval(() => {
    state.timeLeft--;
    updateTimerDisplay();

    if (state.timeLeft <= 0) {
      clearInterval(state.timerId);
      handleTimeout();
    }
  }, 1000);
}

function updateTimerDisplay() {
  const timerEl = document.querySelector('#timer');
  if (!timerEl) return;

  timerEl.textContent = `⏰ ${state.timeLeft}s`;

  // Visual urgency
  timerEl.classList.toggle('timer-warning', state.timeLeft <= 5);
  timerEl.classList.toggle('timer-danger', state.timeLeft <= 3);
}

function handleTimeout() {
  state.answers.push(-1); // -1 = timeout
  showFeedback(-1); // Show correct answer
}

// === EVENT DELEGATION for answer buttons ===
quizContainer.addEventListener('click', (e) => {
  const optionBtn = e.target.closest('.option-btn');
  if (!optionBtn) return;

  // Prevent double-clicking after answering
  if (optionBtn.closest('.answered')) return;

  const selectedIndex = parseInt(optionBtn.dataset.index);
  handleAnswer(selectedIndex);
});

// === KEYBOARD support: press 1-4 to answer ===
document.addEventListener('keydown', (e) => {
  if (state.isFinished) return;

  // Number keys 1-4 to select answer
  const keyNum = parseInt(e.key);
  if (keyNum >= 1 && keyNum <= 4) {
    const optionsContainer = document.querySelector('#options');
    if (optionsContainer && !optionsContainer.classList.contains('answered')) {
      handleAnswer(keyNum - 1); // Convert 1-4 to 0-3 index
    }
  }

  // Enter or Space to go to next question (after answering)
  if ((e.key === 'Enter' || e.key === ' ') && 
      document.querySelector('#next-btn')) {
    e.preventDefault();
    nextQuestion();
  }
});

function handleAnswer(selectedIndex) {
  clearInterval(state.timerId); // Stop the timer

  const q = quizData[state.currentQuestion];
  const isCorrect = selectedIndex === q.correct;

  if (isCorrect) state.score++;
  state.answers.push(selectedIndex);

  showFeedback(selectedIndex);
}

function showFeedback(selectedIndex) {
  const q = quizData[state.currentQuestion];
  const optionsContainer = document.querySelector('#options');
  optionsContainer.classList.add('answered');

  // Highlight correct and wrong answers
  const buttons = optionsContainer.querySelectorAll('.option-btn');
  buttons.forEach((btn, index) => {
    btn.disabled = true; // Disable all buttons

    if (index === q.correct) {
      btn.classList.add('correct'); // Green highlight
    }
    if (index === selectedIndex && selectedIndex !== q.correct) {
      btn.classList.add('wrong');   // Red highlight
    }
  });

  // Show explanation and next button
  const feedbackHTML = `
    <div class="feedback ${selectedIndex === q.correct ? 'feedback-correct' : 'feedback-wrong'}">
      <p class="feedback-icon">${selectedIndex === q.correct ? '✅ Correct!' : 
        selectedIndex === -1 ? '⏰ Time\'s up!' : '❌ Wrong!'}</p>
      <p class="explanation">${q.explanation}</p>
      <button id="next-btn" class="next-btn">
        ${state.currentQuestion < quizData.length - 1 ? 'Next Question →' : 'See Results 🏆'}
      </button>
    </div>
  `;

  quizContainer.insertAdjacentHTML('beforeend', feedbackHTML);

  // Focus next button for keyboard navigation
  document.querySelector('#next-btn').focus();
}

// Next button (using delegation since it's dynamically created)
quizContainer.addEventListener('click', (e) => {
  if (e.target.id === 'next-btn' || e.target.closest('#next-btn')) {
    nextQuestion();
  }
});

function nextQuestion() {
  state.currentQuestion++;

  if (state.currentQuestion >= quizData.length) {
    showResults();
  } else {
    renderQuestion();
  }
}

function showResults() {
  state.isFinished = true;
  clearInterval(state.timerId);

  const percentage = Math.round((state.score / quizData.length) * 100);

  let grade, emoji;
  if (percentage >= 90) { grade = 'Excellent!'; emoji = '🏆'; }
  else if (percentage >= 70) { grade = 'Great job!'; emoji = '🌟'; }
  else if (percentage >= 50) { grade = 'Not bad!'; emoji = '👍'; }
  else { grade = 'Keep practicing!'; emoji = '💪'; }

  quizContainer.innerHTML = `
    <div class="results">
      <h1>${emoji} Quiz Complete!</h1>
      <div class="results-score">
        <div class="score-circle">
          <span class="score-number">${state.score}</span>
          <span class="score-total">/ ${quizData.length}</span>
        </div>
        <p class="score-percentage">${percentage}%</p>
        <p class="score-grade">${grade}</p>
      </div>

      <div class="results-breakdown">
        <h3>Question Breakdown:</h3>
        ${quizData.map((q, index) => {
          const userAnswer = state.answers[index];
          const isCorrect = userAnswer === q.correct;
          const isTimeout = userAnswer === -1;
          return `
            <div class="result-item ${isCorrect ? 'result-correct' : 'result-wrong'}">
              <span class="result-icon">${isCorrect ? '✅' : isTimeout ? '⏰' : '❌'}</span>
              <span class="result-question">${q.question}</span>
              ${!isCorrect ? `
                <span class="result-answer">
                  Your answer: ${isTimeout ? 'Timed out' : q.options[userAnswer]}
                  <br>Correct: ${q.options[q.correct]}
                </span>
              ` : ''}
            </div>
          `;
        }).join('')}
      </div>

      <button id="restart-btn" class="restart-btn">🔄 Restart Quiz</button>
    </div>
  `;
}

// Restart button (delegation)
quizContainer.addEventListener('click', (e) => {
  if (e.target.id === 'restart-btn' || e.target.closest('#restart-btn')) {
    // Reset state
    state.currentQuestion = 0;
    state.score = 0;
    state.answers = [];
    state.isFinished = false;

    renderQuestion();
  }
});

// === START THE QUIZ ===
renderQuestion();

