const form = document.getElementById('registration-form');

form.addEventListener('submit', function(event) {
  event.preventDefault();

  // Read values
  const username = form.elements.username.value.trim();
  const email = form.elements.email.value.trim();
  const age = Number(form.elements.age.value);

  // Track errors
  const errors = [];

  // Validation checks
  if (username === '') {
    errors.push('Username is required');
  }

  if (email === '') {
    errors.push('Email is required');
  }

  if (age < 13 || age > 120) {
    errors.push('Age must be between 13 and 120');
  }

  // Show results
  if (errors.length > 0) {
    console.log('Validation failed:');
    errors.forEach(err => console.log(`  ❌ ${err}`));
  } else {
    console.log('✅ All valid! Processing form...');
    // Process the data here
  }
});

// ===== REUSABLE VALIDATION FUNCTIONS =====

function isEmpty(value) {
  return value.trim() === '';
}

function isTooShort(value, minLength) {
  return value.trim().length < minLength;
}

function isTooLong(value, maxLength) {
  return value.trim().length > maxLength;
}

function isValidEmail(value) {
  // Basic email check: has @, has dot after @
  const atIndex = value.indexOf('@');
  const dotIndex = value.lastIndexOf('.');
  return atIndex > 0 && dotIndex > atIndex + 1 && dotIndex < value.length - 1;
}

function isInRange(num, min, max) {
  return num >= min && num <= max;
}

function hasOnlyLetters(value) {
  for (let char of value) {
    if (!(char >= 'a' && char <= 'z') && !(char >= 'A' && char <= 'Z') && char !== ' ') {
      return false;
    }
  }
  return value.length > 0;
}

// ===== USING THE VALIDATION FUNCTIONS =====

function validateSignupForm(form) {
  const errors = [];
  const username = form.elements.username.value;
  const email = form.elements.email.value;
  const password = form.elements.password.value;
  const age = Number(form.elements.age.value);

  // Username validation
  if (isEmpty(username)) {
    errors.push('Username is required');
  } else if (isTooShort(username, 3)) {
    errors.push('Username must be at least 3 characters');
  } else if (isTooLong(username, 20)) {
    errors.push('Username must be 20 characters or less');
  }

  // Email validation
  if (isEmpty(email)) {
    errors.push('Email is required');
  } else if (!isValidEmail(email)) {
    errors.push('Please enter a valid email address');
  }

  // Password validation
  if (isEmpty(password)) {
    errors.push('Password is required');
  } else if (isTooShort(password, 8)) {
    errors.push('Password must be at least 8 characters');
  }

  // Age validation
  if (isNaN(age) || !isInRange(age, 13, 120)) {
    errors.push('Age must be a number between 13 and 120');
  }

  return errors;
}

// HTML structure:
// <form id="signup-form">
//   <div class="field">
//     <label for="username">Username:</label>
//     <input type="text" id="username" name="username">
//     <span class="error-message" id="username-error"></span>
//   </div>
//   ...
//   <div id="error-summary"></div>
//   <button type="submit">Sign Up</button>
// </form>

function showErrors(errors) {
  // Clear all previous errors first
  clearErrors();

  const summary = document.getElementById('error-summary');

  if (errors.length === 0) return;

  // Show error summary at the top
  summary.innerHTML = `
    <div style="background: #ffe0e0; padding: 10px; border-radius: 5px; margin-bottom: 10px;">
      <strong>⚠️ Please fix ${errors.length} error(s):</strong>
      <ul>
        ${errors.map(err => `<li>${err}</li>`).join('')}
      </ul>
    </div>
  `;
}

function showFieldError(fieldId, message) {
  const input = document.getElementById(fieldId);
  const errorSpan = document.getElementById(`${fieldId}-error`);

  input.style.borderColor = 'red';
  errorSpan.textContent = message;
  errorSpan.style.color = 'red';
  errorSpan.style.fontSize = '0.85em';
}

function clearErrors() {
  // Remove all error styles and messages
  const errorSpans = document.querySelectorAll('.error-message');
  errorSpans.forEach(span => span.textContent = '');

  const inputs = document.querySelectorAll('input');
  inputs.forEach(input => input.style.borderColor = '');

  document.getElementById('error-summary').innerHTML = '';
}

// Usage in submit handler:
form.addEventListener('submit', function(event) {
  event.preventDefault();
  clearErrors();

  const errors = validateSignupForm(form);

  if (errors.length > 0) {
    showErrors(errors);
  } else {
    console.log('✅ Form is valid! Submitting...');
    // Process data
  }
});

