// Track which fields have been touched (blurred at least once)
const touchedFields = new Set();

function setupFieldValidation(inputId, validateFn) {
  const input = document.getElementById(inputId);
  const errorSpan = document.getElementById(`${inputId}-error`);

  // When user LEAVES the field — validate and mark as touched
  input.addEventListener('blur', function() {
    touchedFields.add(inputId);
    const error = validateFn(this.value);
    showFieldState(input, errorSpan, error);
  });

  // While typing — only validate if field was already touched
  input.addEventListener('input', function() {
    if (touchedFields.has(inputId)) {
      const error = validateFn(this.value);
      showFieldState(input, errorSpan, error);
    }
  });
}

function showFieldState(input, errorSpan, errorMessage) {
  if (errorMessage) {
    // INVALID state
    input.classList.remove('valid');
    input.classList.add('invalid');
    errorSpan.textContent = errorMessage;
    errorSpan.style.display = 'block';
  } else {
    // VALID state
    input.classList.remove('invalid');
    input.classList.add('valid');
    errorSpan.textContent = '';
    errorSpan.style.display = 'none';
  }
}

// Set up validation for each field
setupFieldValidation('username', function(value) {
  if (value.trim() === '') return 'Username is required';
  if (value.trim().length < 3) return 'Must be at least 3 characters';
  if (!/^[a-zA-Z0-9_]+$/.test(value)) return 'Only letters, numbers, underscores';
  return null; // null = valid!
});

setupFieldValidation('email', function(value) {
  if (value.trim() === '') return 'Email is required';
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return 'Enter a valid email';
  return null;
});

