// HTML:
// <input type="password" id="password">
// <div id="strength-meter">
//   <div id="strength-bar"></div>
// </div>
// <span id="strength-text"></span>
// <ul id="password-rules"></ul>

const passwordInput = document.getElementById('password');
const strengthBar = document.getElementById('strength-bar');
const strengthText = document.getElementById('strength-text');
const rulesList = document.getElementById('password-rules');

const rules = [
  { test: value => value.length >= 8, label: 'At least 8 characters' },
  { test: value => /[a-z]/.test(value), label: 'One lowercase letter' },
  { test: value => /[A-Z]/.test(value), label: 'One uppercase letter' },
  { test: value => /\d/.test(value), label: 'One number' },
  { test: value => /[!@#$%^&*]/.test(value), label: 'One special character (!@#$%^&*)' },
];

passwordInput.addEventListener('input', function() {
  const password = this.value;
  let passedCount = 0;

  // Check each rule and update the list
  let rulesHTML = '';
  rules.forEach(rule => {
    const passed = rule.test(password);
    if (passed) passedCount++;
    rulesHTML += `<li style="color: ${passed ? '#28a745' : '#999'}">
      ${passed ? '✅' : '⬜'} ${rule.label}
    </li>`;
  });
  rulesList.innerHTML = rulesHTML;

  // Update strength bar
  const percentage = (passedCount / rules.length) * 100;
  strengthBar.style.width = `${percentage}%`;

  // Update strength color and text
  if (passedCount === 0) {
    strengthBar.style.backgroundColor = '#dc3545';
    strengthText.textContent = '';
  } else if (passedCount <= 2) {
    strengthBar.style.backgroundColor = '#dc3545';
    strengthText.textContent = 'Weak';
  } else if (passedCount <= 3) {
    strengthBar.style.backgroundColor = '#ffc107';
    strengthText.textContent = 'Fair';
  } else if (passedCount <= 4) {
    strengthBar.style.backgroundColor = '#28a745';
    strengthText.textContent = 'Good';
  } else {
    strengthBar.style.backgroundColor = '#155724';
    strengthText.textContent = 'Strong!';
  }
});

// Show rules on focus
passwordInput.addEventListener('focus', function() {
  rulesList.style.display = 'block';
});

passwordInput.addEventListener('blur', function() {
  if (this.value === '') {
    rulesList.style.display = 'none';
  }
});

const form = document.getElementById('registration');
const touchedFields = new Set();

// Validation rules for each field
const validators = {
  username: (value) => {
    value = value.trim();
    if (!value) return 'Username is required';
    if (value.length < 3) return 'Too short (min 3 chars)';
    if (value.length > 20) return 'Too long (max 20 chars)';
    if (!/^[a-zA-Z][a-zA-Z0-9_]*$/.test(value)) return 'Must start with a letter, only letters/numbers/underscores';
    return null;
  },
  email: (value) => {
    value = value.trim();
    if (!value) return 'Email is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return 'Enter a valid email address';
    return null;
  },
  password: (value) => {
    if (!value) return 'Password is required';
    if (value.length < 8) return 'Min 8 characters';
    if (!/[A-Z]/.test(value)) return 'Need at least one uppercase letter';
    if (!/\d/.test(value)) return 'Need at least one number';
    return null;
  },
  age: (value) => {
    if (!value) return 'Age is required';
    const num = Number(value);
    if (isNaN(num)) return 'Must be a number';
    if (num < 13 || num > 120) return 'Must be between 13 and 120';
    return null;
  }
};

// Setup real-time validation for all fields
Object.keys(validators).forEach(fieldId => {
  const input = document.getElementById(fieldId);
  const errorSpan = document.getElementById(`${fieldId}-error`);

  input.addEventListener('blur', () => {
    touchedFields.add(fieldId);
    const error = validators[fieldId](input.value);
    updateFieldUI(input, errorSpan, error);
  });

  input.addEventListener('input', () => {
    if (touchedFields.has(fieldId)) {
      const error = validators[fieldId](input.value);
      updateFieldUI(input, errorSpan, error);
    }
  });
});

function updateFieldUI(input, errorSpan, error) {
  input.classList.toggle('invalid', !!error);
  input.classList.toggle('valid', !error);
  errorSpan.textContent = error || '';
}

// Submit handler — final check
form.addEventListener('submit', function(event) {
  event.preventDefault();

  let allValid = true;

  Object.keys(validators).forEach(fieldId => {
    touchedFields.add(fieldId);
    const input = document.getElementById(fieldId);
    const errorSpan = document.getElementById(`${fieldId}-error`);
    const error = validators[fieldId](input.value);
    updateFieldUI(input, errorSpan, error);
    if (error) allValid = false;
  });

  if (allValid) {
    console.log('🎉 Form is valid! Submitting...');
    const data = {
      username: form.elements.username.value.trim(),
      email: form.elements.email.value.trim(),
      password: form.elements.password.value,
      age: Number(form.elements.age.value)
    };
    console.log('Data:', data);
    // Send to server...
  } else {
    console.log('❌ Fix errors above before submitting');
  }
});

