// ===== DATA LAYER =====
// This array is our SINGLE SOURCE OF TRUTH
let todos = [];
let nextId = 1; // Simple ID counter

// ===== DOM REFERENCES =====
const form = document.getElementById('todo-form');
const input = document.getElementById('todo-input');
const errorMsg = document.getElementById('error-message');
const list = document.getElementById('todo-list');
const stats = document.getElementById('stats');

// ===== ADD TODO =====
form.addEventListener('submit', function(event) {
  event.preventDefault();

  const text = input.value.trim();

  // Validate
  if (text === '') {
    errorMsg.textContent = 'Please enter a task!';
    input.focus();
    return; // Stop here — don't add empty todos
  }

  if (text.length > 100) {
    errorMsg.textContent = 'Task is too long (max 100 characters)';
    return;
  }

  // Check for duplicates
  const duplicate = todos.find(
    todo => todo.text.toLowerCase() === text.toLowerCase()
  );
  if (duplicate) {
    errorMsg.textContent = 'This task already exists!';
    return;
  }

  // Clear any previous error
  errorMsg.textContent = '';

  // Create the todo object
  const newTodo = {
    id: nextId++,
    text: text,
    done: false,
    createdAt: new Date().toLocaleString()
  };

  // Add to our data array
  todos.push(newTodo);

  // Re-render the DOM
  renderList();

  // Clear the input and refocus
  input.value = '';
  input.focus();

  console.log('Added:', newTodo);
  console.log('All todos:', todos);
});

// ===== RENDER FUNCTION =====
// This function rebuilds the ENTIRE list from the array
function renderList() {
  // Clear the list
  list.innerHTML = '';

  // If no todos, show a message
  if (todos.length === 0) {
    list.innerHTML = '<li style="color: #999; padding: 20px; text-align: center;">No tasks yet. Add one above! 👆</li>';
    stats.textContent = '';
    return;
  }

  // Build each list item
  todos.forEach(function(todo) {
    const li = document.createElement('li');
    li.className = `todo-item ${todo.done ? 'done' : ''}`;
    li.dataset.id = todo.id; // Store the ID on the element

    li.innerHTML = `
      <input type="checkbox" ${todo.done ? 'checked' : ''} class="toggle-checkbox">
      <span class="todo-text">${escapeHTML(todo.text)}</span>
      <button class="delete-btn" title="Delete task">✕</button>
    `;

    list.appendChild(li);
  });

  // Update stats
  const doneCount = todos.filter(t => t.done).length;
  stats.textContent = `${doneCount} of ${todos.length} tasks completed`;
}

// ===== SECURITY: Escape HTML to prevent XSS =====
function escapeHTML(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

// Initial render
renderList();

sections.content:
NEVER insert user input directly into `.innerHTML` without escaping it first!

```javascript
// ❌ DANGEROUS — User could inject malicious scripts
li.innerHTML = `<span>${userInput}</span>`;

// ✅ SAFE — Escape HTML entities
li.innerHTML = `<span>${escapeHTML(userInput)}</span>`;

// ✅ ALSO SAFE — Use textContent (no HTML parsing)
const span = document.createElement('span');
span.textContent = userInput;
li.appendChild(span);
```
If a user types `<img src=x onerror=alert('hacked')>` and you put it in innerHTML unescaped, their JavaScript code runs on your page. This is called Cross-Site Scripting (XSS) and it's one of the most common web security vulnerabilities.

