// Some developers prefer creating elements manually
// for better security (no HTML parsing at all)

function renderListSafe() {
  list.innerHTML = '';  // Still clear the container

  todos.forEach(function(todo) {
    // Create elements
    const li = document.createElement('li');
    li.className = `todo-item ${todo.done ? 'done' : ''}`;
    li.dataset.id = todo.id;

    const checkbox = document.createElement('input');
    checkbox.type = 'checkbox';
    checkbox.checked = todo.done;
    checkbox.className = 'toggle-checkbox';

    const span = document.createElement('span');
    span.className = 'todo-text';
    span.textContent = todo.text;  // textContent is XSS-safe!

    const deleteBtn = document.createElement('button');
    deleteBtn.className = 'delete-btn';
    deleteBtn.textContent = '✕';
    deleteBtn.title = 'Delete task';

    // Assemble
    li.appendChild(checkbox);
    li.appendChild(span);
    li.appendChild(deleteBtn);
    list.appendChild(li);
  });
}

