  { id: 2, text: 'Walk the dog', done: true },
  { id: 3, text: 'Write code', done: false }
];

const list = document.getElementById('todo-list');

// Event delegation on the parent <ul>
list.addEventListener('click', function(event) {
  // Get the list item (li) that contains whatever was clicked
  const li = event.target.closest('.todo-item');
  if (!li) return; // Click wasn't inside a todo item

  // Get the todo's ID from the data attribute
  const todoId = Number(li.dataset.id);

  // Handle DELETE
  if (event.target.classList.contains('delete-btn')) {
    deleteTodo(todoId);
  }

  // Handle TOGGLE (checkbox)
  if (event.target.classList.contains('toggle-checkbox')) {
    toggleTodo(todoId);
  }
});

function deleteTodo(id) {
  // Step 1: Remove from array
  todos = todos.filter(todo => todo.id !== id);

  // Step 2: Re-render
  renderList();

  console.log(`Deleted todo ${id}. Remaining:`, todos.length);
}

function toggleTodo(id) {
  // Step 1: Find and toggle in array
  const todo = todos.find(todo => todo.id === id);
  if (todo) {
    todo.done = !todo.done;
  }

  // Step 2: Re-render
  renderList();

  console.log(`Toggled todo ${id}:`, todo.done ? 'done' : 'not done');
}

sections.content:
`.closest(selector)` is incredibly useful for event delegation. Starting from the element, it walks UP the DOM tree looking for the first ancestor matching the selector.

```javascript
// If user clicks the ✕ text inside the delete button:
// <li data-id="3" class="todo-item">
//   <button class="delete-btn">✕</button>  ← clicked here
// </li>

event.target                          // The <button>
event.target.closest('.todo-item')    // The <li>
event.target.closest('.todo-item').dataset.id  // "3"
```
Without `.closest()`, if someone clicks the text inside a button, `event.target` might be the text node rather than the button itself. `.closest()` handles this gracefully.

