// Add to the event delegation handler:
list.addEventListener('dblclick', function(event) {
  const li = event.target.closest('.todo-item');
  if (!li) return;
  if (!event.target.classList.contains('todo-text')) return;

  const todoId = Number(li.dataset.id);
  const todo = todos.find(t => t.id === todoId);
  if (!todo || todo.done) return; // Don't edit completed items

  startEditing(li, todo);
});

function startEditing(li, todo) {
  const span = li.querySelector('.todo-text');

  // Replace span with an input
  const editInput = document.createElement('input');
  editInput.type = 'text';
  editInput.value = todo.text;
  editInput.className = 'edit-input';
  editInput.style.cssText = 'flex: 1; padding: 4px 8px; font-size: 16px; margin: 0 12px;';

  span.replaceWith(editInput);
  editInput.focus();
  editInput.select(); // Select all text

  // Save on Enter
  editInput.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') {
      finishEditing(editInput, todo);
    }
    if (e.key === 'Escape') {
      renderList(); // Cancel edit — re-render original
    }
  });

  // Save on blur (clicking away)
  editInput.addEventListener('blur', function() {
    finishEditing(editInput, todo);
  });
}

function finishEditing(input, todo) {
  const newText = input.value.trim();

  if (newText === '') {
    // If emptied, delete the todo
    deleteTodo(todo.id);
  } else if (newText !== todo.text) {
    // Update the data
    todo.text = newText;
  }

  // Re-render to show the updated text
  renderList();
}

// One delegated handler for ALL list interactions
const list = document.getElementById('todo-list');

list.addEventListener('click', function(event) {
  const li = event.target.closest('.todo-item');
  if (!li) return;

  const id = Number(li.dataset.id);

  // DELETE
  if (event.target.matches('.delete-btn')) {
    if (confirm('Delete this task?')) {
      todos = todos.filter(t => t.id !== id);
      renderList();
    }
  }

  // TOGGLE
  if (event.target.matches('.toggle-checkbox')) {
    const todo = todos.find(t => t.id === id);
    if (todo) todo.done = !todo.done;
    renderList();
  }
});

// EDIT (double-click)
list.addEventListener('dblclick', function(event) {
  if (event.target.matches('.todo-text')) {
    const li = event.target.closest('.todo-item');
    const id = Number(li.dataset.id);
    const todo = todos.find(t => t.id === id);
    if (todo && !todo.done) startEditing(li, todo);
  }
});

// ===== BONUS: Filter Buttons =====
function filterTodos(filter) {
  let filtered;
  switch (filter) {
    case 'active':
      filtered = todos.filter(t => !t.done);
      break;
    case 'completed':
      filtered = todos.filter(t => t.done);
      break;
    default:
      filtered = todos;
  }
  renderFilteredList(filtered);
}

// Bonus: Clear all completed
function clearCompleted() {
  todos = todos.filter(t => !t.done);
  renderList();
}

