sections.code:
// ===== SAVING ARRAYS/OBJECTS =====
const todos = [
  { id: 1, text: 'Buy milk', done: false },
  { id: 2, text: 'Walk dog', done: true },
  { id: 3, text: 'Code', done: false }
];

// Convert to JSON string first
const jsonString = JSON.stringify(todos);
console.log(jsonString);
// '[{"id":1,"text":"Buy milk","done":false},{"id":2,...}]'
console.log(typeof jsonString);  // 'string' — perfect for localStorage!

// Save it
localStorage.setItem('todos', jsonString);

// ===== LOADING ARRAYS/OBJECTS =====
// Read the JSON string
const stored = localStorage.getItem('todos');
console.log(typeof stored);  // 'string'

// Parse back into a real JavaScript array
const loadedTodos = JSON.parse(stored);
console.log(Array.isArray(loadedTodos));  // true — it's an array again!
