// ===== DATA LAYER =====
let tasks = JSON.parse(localStorage.getItem('tasks') || '[]');
let currentFilter = 'all';
let searchTerm = '';

function generateId() {
  return Date.now().toString(36) + Math.random().toString(36).substr(2);
}

function addTask(title, priority, dueDate) {
  tasks.unshift({
    id: generateId(),
    title: title.trim(),
    priority,
    dueDate: dueDate || null,
    completed: false,
    createdAt: new Date().toISOString()
  });
  saveTasks();
}

function deleteTask(id) {
  tasks = tasks.filter(t => t.id !== id);
  saveTasks();
}

function toggleTask(id) {
  const task = tasks.find(t => t.id === id);
  if (task) { task.completed = !task.completed; saveTasks(); }
}

function editTask(id, newTitle) {
  const task = tasks.find(t => t.id === id);
  if (task && newTitle.trim()) { task.title = newTitle.trim(); saveTasks(); }
}

function saveTasks() {
  localStorage.setItem('tasks', JSON.stringify(tasks));
}

// ===== FILTER & SEARCH =====
function getFilteredTasks() {
  return tasks.filter(task => {
    if (currentFilter === 'active' && task.completed) return false;
    if (currentFilter === 'completed' && !task.completed) return false;
    if (searchTerm && !task.title.toLowerCase().includes(searchTerm.toLowerCase())) return false;
    return true;
  });
}

// ===== RENDER =====
function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

function renderTasks() {
  const list = document.querySelector('#task-list');
  const filtered = getFilteredTasks();

  if (filtered.length === 0) {
    list.innerHTML = '<li class="empty">No tasks found 🎉</li>';
  } else {
    list.innerHTML = filtered.map(task => `
      <li class="task ${task.completed ? 'completed' : ''} priority-${task.priority}" data-id="${task.id}">
        <input type="checkbox" ${task.completed ? 'checked' : ''} class="toggle">
        <span class="task-title">${escapeHtml(task.title)}</span>
        ${task.dueDate ? `<span class="due-date">${new Date(task.dueDate + 'T00:00:00').toLocaleDateString()}</span>` : ''}
        <button class="edit-btn">✏️</button>
        <button class="delete-btn">🗑️</button>
      </li>
    `).join('');
  }

  const total = tasks.length;
  const completed = tasks.filter(t => t.completed).length;
  document.querySelector('#stats').textContent = `${total - completed} active · ${completed} completed · ${total} total`;
}

// ===== VALIDATION =====
function validateTask(title) {
  if (!title.trim()) return ['Task title is required'];
  if (title.trim().length < 3) return ['Title must be at least 3 characters'];
  if (title.trim().length > 200) return ['Title must be under 200 characters'];
  return [];
}

// ===== EVENT HANDLERS =====
document.querySelector('#task-form').addEventListener('submit', (e) => {
  e.preventDefault();
  const title = document.querySelector('#task-title');
  const errors = validateTask(title.value);
  if (errors.length > 0) { alert(errors[0]); return; }
  addTask(title.value, document.querySelector('#task-priority').value, document.querySelector('#task-due').value);
  e.target.reset();
  renderTasks();
});

document.querySelector('#task-list').addEventListener('click', (e) => {
  const taskEl = e.target.closest('.task');
  if (!taskEl) return;
  const id = taskEl.dataset.id;
  if (e.target.classList.contains('toggle')) { toggleTask(id); renderTasks(); }
  else if (e.target.classList.contains('delete-btn')) { deleteTask(id); renderTasks(); }
  else if (e.target.classList.contains('edit-btn')) {
    const newTitle = prompt('Edit task:', taskEl.querySelector('.task-title').textContent);
    if (newTitle !== null) { editTask(id, newTitle); renderTasks(); }
  }
});

document.querySelector('#search').addEventListener('input', (e) => {
  searchTerm = e.target.value;
  renderTasks();
});

document.querySelector('#filters').addEventListener('click', (e) => {
  if (!e.target.classList.contains('filter')) return;
  document.querySelectorAll('.filter').forEach(b => b.classList.remove('active'));
  e.target.classList.add('active');
  currentFilter = e.target.dataset.filter;
  renderTasks();
});

renderTasks();

