// Custom error for validation failures
class ValidationError extends Error {
  constructor(field, message) {
    super(message);           // Call parent Error constructor
    this.name = "ValidationError";
    this.field = field;       // Custom property!
  }
}

// Custom error for "not found" situations
class NotFoundError extends Error {
  constructor(resource, id) {
    super(`${resource} with ID ${id} was not found`);
    this.name = "NotFoundError";
    this.resource = resource;
    this.id = id;
  }
}

// Using custom errors
function getUser(id) {
  if (typeof id !== "number") {
    throw new ValidationError("id", "User ID must be a number");
  }

  // Simulate: user with this ID doesn't exist
  let database = { 1: "Alice", 2: "Bob" };
  if (!database[id]) {
    throw new NotFoundError("User", id);
  }

  return { id, name: database[id] };
}

