// ❌ WITHOUT guard clauses — deeply nested, hard to read
function processOrder(order) {
  if (order) {
    if (order.items) {
      if (order.items.length > 0) {
        if (order.customer) {
          // Finally do the actual work here...
          let total = order.items.reduce((sum, item) => sum + item.price, 0);
          return { customer: order.customer, total };
        }
      }
    }
  }
  return null;
}

// ✅ WITH guard clauses — flat, clean, easy to read
function processOrder(order) {
  if (!order) throw new Error("Order is required");
  if (!order.items) throw new Error("Order must have items");
  if (order.items.length === 0) throw new Error("Order must have at least one item");
  if (!order.customer) throw new Error("Order must have a customer");

  // If we get here, we know everything is valid!
  let total = order.items.reduce((sum, item) => sum + item.price, 0);
  return { customer: order.customer, total };
}

