// These helper functions handle all the edge cases for you.
// Use them in your projects!

function saveToStorage(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
    return true;
  } catch (error) {
    // localStorage might be full or disabled
    console.error(`Failed to save '${key}':`, error.message);
    return false;
  }
}

function loadFromStorage(key, defaultValue = null) {
  try {
    const item = localStorage.getItem(key);
    // If the key doesn't exist, return the default
    if (item === null) return defaultValue;
    return JSON.parse(item);
  } catch (error) {
    // If JSON.parse fails (corrupted data), return the default
    console.error(`Failed to load '${key}':`, error.message);
    return defaultValue;
  }
}

function removeFromStorage(key) {
  localStorage.removeItem(key);
}


