// Yes, that's a single string with ALL cookies concatenated.
// No, there's no built-in .getCookie() method. We need to parse it.

// Helper function to get a specific cookie by name:
function getCookie(name) {
  const cookies = document.cookie.split("; ");

  for (let cookie of cookies) {
    const [key, value] = cookie.split("=");
    if (key === name) {
      return decodeURIComponent(value);
    }
  }
  return null;  // Cookie not found
}

// Usage:
let username = getCookie("username");
console.log(username);  // "alice" or null

// Setting a basic cookie
document.cookie = "username=alice";
// This does NOT overwrite all cookies!
// It adds/updates only the 'username' cookie.

// Setting a cookie with an expiration date
let expiryDate = new Date();
expiryDate.setDate(expiryDate.getDate() + 7);  // 7 days from now

document.cookie = `theme=dark; expires=${expiryDate.toUTCString()}`;

// Setting a cookie with max-age (seconds)
document.cookie = "language=en; max-age=86400";  // 24 hours (60*60*24)

// Setting a cookie with path
document.cookie = "sidebar=collapsed; path=/";  // Available on all pages

// Setting a secure cookie (HTTPS only)
document.cookie = "token=abc123; secure; sameSite=strict";

// Full example with all attributes:
document.cookie = [
  "sessionId=xyz789",
  `expires=${expiryDate.toUTCString()}`,
  "path=/",
  "secure",
  "sameSite=strict"
].join("; ");

// To delete a cookie, set it with an expiration date in the PAST

// Delete the 'username' cookie:
document.cookie = "username=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;";

// Or use max-age=0:
document.cookie = "theme=; max-age=0; path=/;";

// Helper function:
function deleteCookie(name) {
  document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
}

// Usage:
deleteCookie("username");
deleteCookie("theme");

// A reusable cookie utility object
const CookieUtil = {

  get(name) {
    const cookies = document.cookie.split("; ");
    for (let cookie of cookies) {
      const [key, ...valueParts] = cookie.split("=");
      if (key === name) {
        return decodeURIComponent(valueParts.join("="));
      }
    }
    return null;
  },

  set(name, value, days = 7, path = "/") {
    let cookie = `${name}=${encodeURIComponent(value)}`;

    if (days) {
      const expires = new Date();
      expires.setDate(expires.getDate() + days);
      cookie += `; expires=${expires.toUTCString()}`;
    }

    cookie += `; path=${path}`;
    cookie += "; sameSite=lax";

    document.cookie = cookie;
  },

  delete(name, path = "/") {
    document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=${path};`;
  },

  getAll() {
    if (!document.cookie) return {};

    const result = {};
    document.cookie.split("; ").forEach(cookie => {
      const [key, ...valueParts] = cookie.split("=");
      result[key] = decodeURIComponent(valueParts.join("="));
    });
    return result;
  }
};

// Usage:
CookieUtil.set("username", "alice", 30);  // Expires in 30 days
CookieUtil.set("theme", "dark", 365);     // Expires in 1 year

console.log(CookieUtil.get("username"));  // "alice"
console.log(CookieUtil.getAll());         // { username: "alice", theme: "dark" }

CookieUtil.delete("username");
console.log(CookieUtil.get("username"));  // null

