// ===== STORAGE SERVICE =====
const StorageService = {
  DATA_KEY: 'notes_app_data',
  VERSION: 2,

  save(notes) {
    try {
      const data = { version: this.VERSION, notes, lastSaved: new Date().toISOString() };
      localStorage.setItem(this.DATA_KEY, JSON.stringify(data));
      return true;
    } catch (e) {
      console.warn('Storage save failed:', e.message);
      return false;
    }
  },

  load() {
    try {
      const raw = localStorage.getItem(this.DATA_KEY);
      if (!raw) return [];
      const data = JSON.parse(raw);
      if (!data.version || data.version < this.VERSION) {
        return this.migrate(data);
      }
      return data.notes || [];
    } catch (e) {
      console.warn('Storage load failed:', e.message);
      return [];
    }
  },

  migrate(oldData) {
    if (Array.isArray(oldData)) {
      return oldData.map(note => ({ ...note, tags: note.tags || [], pinned: false }));
    }
    return (oldData.notes || []).map(n => ({ ...n, tags: n.tags || [], pinned: false }));
  }
};

// ===== APP =====
let notes = StorageService.load();
let searchTerm = '';

function createNote(title, body) {
  if (!title?.trim()) throw new Error('Title is required');
  const note = {
    id: Date.now().toString(36) + Math.random().toString(36).substr(2),
    title: title.trim(), body: body?.trim() || '',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    pinned: false, tags: []
  };
  notes.unshift(note);
  StorageService.save(notes);
  return note;
}

function deleteNote(id) { notes = notes.filter(n => n.id !== id); StorageService.save(notes); }

function updateNote(id, updates) {
  const note = notes.find(n => n.id === id);
  if (!note) throw new Error('Note not found');
  Object.assign(note, updates, { updatedAt: new Date().toISOString() });
  StorageService.save(notes);
}

function exportNotes() {
  try {
    const blob = new Blob([JSON.stringify(notes, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'notes-export.json'; a.click();
    URL.revokeObjectURL(url);
  } catch (e) { alert('Export failed: ' + e.message); }
}

function renderNotes() {
  const container = document.querySelector('#notes-list');
  const filtered = notes.filter(n => !searchTerm || 
    n.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    n.body.toLowerCase().includes(searchTerm.toLowerCase()));
  container.innerHTML = filtered.length === 0
    ? '<p class="empty">No notes yet. Create one!</p>'
    : filtered.map(n => `
      <div class="note ${n.pinned ? 'pinned' : ''}" data-id="${n.id}">
        <h3>${n.title}</h3>
        <p>${n.body.substring(0, 100)}${n.body.length > 100 ? '...' : ''}</p>
        <small>${new Date(n.updatedAt).toLocaleDateString()}</small>
        <button class="edit-btn">✏️</button>
        <button class="delete-btn">🗑️</button>
