// Base class for all UI components
class Component {
  constructor(selector) {
    this.element = document.querySelector(selector);
    if (!this.element) {
      throw new Error(`Element not found: ${selector}`);
    }
    this.isVisible = true;
  }

  show() {
    this.element.classList.remove('hidden');
    this.isVisible = true;
  }

  hide() {
    this.element.classList.add('hidden');
    this.isVisible = false;
  }

  toggle() {
    this.isVisible ? this.hide() : this.show();
  }
}

// Modal extends Component — gets show/hide/toggle for free!
class Modal extends Component {
  constructor(selector) {
    super(selector);
    this.isOpen = false;

    // Close on Escape key
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && this.isOpen) this.close();
    });

    // Close on overlay click
    this.element.addEventListener('click', (e) => {
      if (e.target === this.element) this.close();
    });
  }

  open() {
    this.show();  // Inherited from Component!
    this.isOpen = true;
    document.body.style.overflow = 'hidden';
  }

  close() {
    this.hide();  // Inherited from Component!
    this.isOpen = false;
    document.body.style.overflow = '';
  }
}

// Tooltip extends Component
class Tooltip extends Component {
  constructor(selector, text) {
    super(selector);
    this.text = text;
    this.tooltipEl = null;

    this.element.addEventListener('mouseenter', () => this.showTooltip());
    this.element.addEventListener('mouseleave', () => this.hideTooltip());
  }

  showTooltip() {
    this.tooltipEl = document.createElement('div');
    this.tooltipEl.className = 'tooltip-popup';
    this.tooltipEl.textContent = this.text;
    this.element.appendChild(this.tooltipEl);
  }

  hideTooltip() {
    if (this.tooltipEl) {
      this.tooltipEl.remove();
      this.tooltipEl = null;
    }
  }
}

// Both Modal and Tooltip inherit show/hide/toggle from Component
// const modal = new Modal('#my-modal');
// const tip = new Tooltip('#help-icon', 'Click here for help');

sections.content:
If your child class has a constructor, you MUST follow these rules:

1. **Call `super(...)` BEFORE using `this`** — JavaScript needs to set up the parent first
2. **Pass the required arguments** — `super(name, age)` calls `constructor(name, age)` on the parent
3. **If you don't write a constructor**, the child automatically uses the parent's constructor

javascript
// ❌ ERROR: Must call super() before using 'this'
class Dog extends Animal {
  constructor(name, breed) {
    this.breed = breed;    // ReferenceError!
    super(name);           // Too late!
  }
}

// ✅ CORRECT
class Dog extends Animal {
  constructor(name, breed) {
    super(name);           // Parent setup first
    this.breed = breed;    // Now 'this' is available
  }
}

// ✅ No constructor needed if child adds no new properties
class Dog extends Animal {
  bark() { console.log('Woof!'); }
  // Uses Animal's constructor automatically
}

