    }
    this.balance -= amount;
    return true;
  }
}

const account = new BankAccount('Alice', 1000);

// The withdraw method has validation... but who needs it? 😈
account.balance = 999999999;  // Direct access — no validation!
account.balance = -500;       // Negative balance? Sure!
account.balance = 'lots';     // String balance? Why not!

console.log(account.balance); // 'lots' — this is broken 💀

// All our careful validation in withdraw() is useless
// because anyone can bypass it by accessing balance directly.

class BankAccount {
  // Private fields — declared with # prefix
  #balance;
  #pin;
  #transactionLog;

  constructor(owner, initialBalance, pin) {
    this.owner = owner;                   // Public — anyone can read/write
    this.#balance = initialBalance;       // Private — only this class can access
    this.#pin = pin;                      // Private — PIN is secret!
    this.#transactionLog = [];            // Private — internal bookkeeping
  }

  // Public method — controlled access to balance
  getBalance(pin) {
    if (!this.#verifyPin(pin)) {
      console.log('❌ Wrong PIN!');
      return null;
    }
    return this.#balance;
  }

  deposit(amount) {
    if (amount <= 0) {
      console.log('❌ Amount must be positive');
      return false;
    }
    this.#balance += amount;
    this.#logTransaction('deposit', amount);
    console.log(`✅ Deposited $${amount}`);
    return true;
  }

  withdraw(amount, pin) {
    if (!this.#verifyPin(pin)) {
      console.log('❌ Wrong PIN!');
      return false;
    }
    if (amount <= 0 || amount > this.#balance) {
      console.log('❌ Invalid amount or insufficient funds');
      return false;
    }
    this.#balance -= amount;
    this.#logTransaction('withdrawal', amount);
    console.log(`✅ Withdrew $${amount}`);
    return true;
  }

  // Private methods — internal helpers
  #verifyPin(pin) {
    return pin === this.#pin;
  }

  #logTransaction(type, amount) {
    this.#transactionLog.push({
      type,
      amount,
      date: new Date(),
      balanceAfter: this.#balance
    });
