// Only the class itself can access # fields!

class User {
  #email;
  #passwordHash;
  #loginAttempts;
  static #MAX_ATTEMPTS = 5;

  constructor(name, email, password) {
    this.name = name;                    // Public
    this.#email = email;                 // Private
    this.#passwordHash = this.#hash(password); // Private
    this.#loginAttempts = 0;             // Private
  }

  // Getter — controlled read access to email
  get email() {
    return this.#email;
  }

  // Setter — validated write access to email
  set email(newEmail) {
    if (!newEmail.includes('@')) {
      throw new Error('Invalid email format');
    }
    this.#email = newEmail;
    console.log('📧 Email updated successfully');
  }

  // Private method
  #hash(password) {
    // In reality, use a proper hashing library!
    let hash = 0;
    for (const char of password) {
      hash = ((hash << 5) - hash) + char.charCodeAt(0);
      hash = hash & hash; // Convert to 32-bit integer
    }
    return hash.toString(16);
  }

  login(password) {
    if (this.#loginAttempts >= User.#MAX_ATTEMPTS) {
      console.log('🔒 Account locked! Too many failed attempts.');
      return false;
    }

    if (this.#hash(password) === this.#passwordHash) {
      this.#loginAttempts = 0;
      console.log(`✅ Welcome back, ${this.name}!`);
      return true;
    }

    this.#loginAttempts++;
    const remaining = User.#MAX_ATTEMPTS - this.#loginAttempts;
    console.log(`❌ Wrong password. ${remaining} attempts remaining.`);
    return false;
  }

  changePassword(oldPassword, newPassword) {
    if (this.#hash(oldPassword) !== this.#passwordHash) {
      console.log('❌ Current password incorrect');
      return false;
    }
    this.#passwordHash = this.#hash(newPassword);
    console.log('✅ Password changed successfully');
    return true;
  }
}

