// ✅ Composition: Build behaviors as separate, reusable pieces

// Behavior modules (plain objects or functions that add abilities)
const canWalk = (self) => ({
  walk() {
    console.log(`${self.name} walks on ${self.legs || 2} legs.`);
  }
});

const canSwim = (self) => ({
  swim() {
    console.log(`${self.name} swims through the water! 🏊`);
  }
});

const canFly = (self) => ({
  fly() {
    console.log(`${self.name} soars through the sky! 🦅`);
  }
});

const canBark = (self) => ({
  bark() {
    console.log(`${self.name} says: Woof! 🐕`);
  }
});

// Compose behaviors — mix and match!
function createDog(name) {
  const self = { name, legs: 4, type: 'dog' };
  return Object.assign(self, canWalk(self), canBark(self));
}

function createDuck(name) {
  const self = { name, legs: 2, type: 'duck' };
  return Object.assign(self, canWalk(self), canSwim(self), canFly(self));
}

function createSwimmingDog(name) {
  const self = { name, legs: 4, type: 'swimming-dog' };
  return Object.assign(self, canWalk(self), canBark(self), canSwim(self));
}

// Each has exactly the abilities it needs!
const rex = createDog('Rex');
rex.walk();  // Rex walks on 4 legs.
rex.bark();  // Rex says: Woof! 🐕

const donald = createDuck('Donald');
donald.walk();  // Donald walks on 2 legs.
donald.swim();  // Donald swims through the water! 🏊
