class Character {
  #hp;
  #maxHp;
  #level;
  #experience;
  #alive;

  constructor(name, characterClass, baseHp, baseAttack, baseDefense) {
    this.name = name;
    this.characterClass = characterClass;
    this.#hp = baseHp;
    this.#maxHp = baseHp;
    this.#level = 1;
    this.#experience = 0;
    this.#alive = true;
    this.baseAttack = baseAttack;
    this.baseDefense = baseDefense;

    // Composition: Character HAS an Inventory
    this.inventory = new Inventory(20);
    this.gold = 0;
  }

  // --- Getters ---
  get hp() { return this.#hp; }
  get maxHp() { return this.#maxHp; }
  get level() { return this.#level; }
  get experience() { return this.#experience; }
  get isAlive() { return this.#alive; }

  get expToNextLevel() {
    return this.#level * 100 - this.#experience;
  }

  // --- Core Methods ---

  // Polymorphic — subclasses will override this
  attack(target) {
    if (!this.#alive) {
      console.log(`💀 ${this.name} is defeated and can't attack!`);
      return 0;
    }
    const damage = Math.max(1, this.baseAttack - target.baseDefense + 
      Math.floor(Math.random() * 5));
    console.log(`⚔️ ${this.name} attacks ${target.name} for ${damage} damage!`);
    target.takeDamage(damage);
    return damage;
  }

  // Polymorphic — each subclass has a unique ability
  specialAbility(target) {
    console.log(`${this.name} has no special ability.`);
  }

  takeDamage(amount) {
    if (!this.#alive) return;
    this.#hp = Math.max(0, this.#hp - amount);
    console.log(`💔 ${this.name} takes ${amount} damage! HP: ${this.#hp}/${this.#maxHp}`);
    if (this.#hp === 0) {
      this.#alive = false;
      console.log(`💀 ${this.name} has been defeated!`);
    }
  }

  heal(amount) {
    if (!this.#alive) {
      console.log(`💀 Cannot heal ${this.name} — they are defeated!`);
      return;
    }
    const actualHeal = Math.min(amount, this.#maxHp - this.#hp);
    this.#hp += actualHeal;
    console.log(`💚 ${this.name} heals for ${actualHeal}! HP: ${this.#hp}/${this.#maxHp}`);
  }

  gainExperience(amount) {
    if (!this.#alive) return;
    this.#experience += amount;
    console.log(`✨ ${this.name} gains ${amount} XP! (${this.#experience}/${this.#level * 100})`);

    while (this.#experience >= this.#level * 100) {
      this.#experience -= this.#level * 100;
      this.#levelUp();
    }
  }

  #levelUp() {
    this.#level++;
    const hpIncrease = 10 + Math.floor(Math.random() * 10);
    this.#maxHp += hpIncrease;
    this.#hp = this.#maxHp; // Full heal on level up
    this.baseAttack += 2;
    this.baseDefense += 1;
    console.log(`🎉 ${this.name} reached LEVEL ${this.#level}! HP: +${hpIncrease}, ATK: +2, DEF: +1`);
  }

  status() {
    const healthBar = this.#getHealthBar();
    console.log(`\n--- ${this.name} the ${this.characterClass} ---`);
    console.log(`  Level: ${this.#level} | XP: ${this.#experience}/${this.#level * 100}`);
    console.log(`  HP: ${healthBar} ${this.#hp}/${this.#maxHp}`);
    console.log(`  ATK: ${this.baseAttack} | DEF: ${this.baseDefense}`);
    console.log(`  Gold: ${this.gold}`);
    console.log(`  ${this.#alive ? '✅ Alive' : '💀 Defeated'}`);
  }

  #getHealthBar() {
    const percentage = this.#hp / this.#maxHp;
    const filled = Math.round(percentage * 10);
    const empty = 10 - filled;
    return '[' + '█'.repeat(filled) + '░'.repeat(empty) + ']';
  }

  // Static factory method
  static createRandom(name) {
    const classes = ['Warrior', 'Mage', 'Archer'];
    const randomClass = classes[Math.floor(Math.random() * classes.length)];
    // We'll implement the specific subclasses next
    return { name, class: randomClass };
  }
}

