// Battle simulator using polymorphism!
class Battle {
  static fight(char1, char2) {
    console.log('\n⚔️═══════════════════════════════════════⚔️');
    console.log(`  ${char1.name} the ${char1.characterClass}`);
    console.log(`         VS`);
    console.log(`  ${char2.name} the ${char2.characterClass}`);
    console.log('⚔️═══════════════════════════════════════⚔️\n');

    let round = 1;

    while (char1.isAlive && char2.isAlive) {
      console.log(`--- Round ${round} ---`);

      // Character 1 attacks
      if (char1.isAlive) {
        if (round % 4 === 0) {
          char1.specialAbility(char2); // Special every 4th round
        } else {
          char1.attack(char2);         // Normal attack
        }
      }

      // Character 2 attacks (if still alive)
      if (char2.isAlive) {
        if (round % 4 === 0) {
          char2.specialAbility(char1);
        } else {
          char2.attack(char1);
        }
      }

      round++;
      console.log('');

      if (round > 50) {
        console.log('⏰ Battle timeout! It\'s a draw!');
        break;
      }
    }

    const winner = char1.isAlive ? char1 : char2;
    const loser = char1.isAlive ? char2 : char1;

    console.log('═══════════════════════════════════════');
    console.log(`🏆 ${winner.name} the ${winner.characterClass} WINS!`);
    console.log('═══��═══════════════════════════════════\n');

    winner.gainExperience(50 + loser.level * 20);
    winner.gold += 30;

    return winner;
  }

  // Static method: tournament with multiple characters
  static tournament(characters) {
    console.log('\n🏟️  GRAND TOURNAMENT BEGINS! 🏟️');
    console.log(`${characters.length} fighters enter...\n`);

    let remaining = [...characters];
    let roundNum = 1;

    while (remaining.length > 1) {
      console.log(`\n=== Tournament Round ${roundNum} ===`);
      const nextRound = [];

      for (let i = 0; i < remaining.length; i += 2) {
        if (i + 1 < remaining.length) {
          // Heal both fighters before the match
          remaining[i].heal(remaining[i].maxHp);
          remaining[i + 1].heal(remaining[i + 1].maxHp);

          const winner = Battle.fight(remaining[i], remaining[i + 1]);
          nextRound.push(winner);
        } else {
          console.log(`${remaining[i].name} gets a bye!`);
          nextRound.push(remaining[i]);
        }
      }

      remaining = nextRound;
      roundNum++;
    }

    console.log(`\n🏆🏆🏆 TOURNAMENT CHAMPION: ${remaining[0].name} the ${remaining[0].characterClass}! 🏆🏆🏆`);
    remaining[0].status();
    return remaining[0];
  }
}

