// Synchronous: Each line waits for the previous one to finish
console.log('1. First');
console.log('2. Second');
console.log('3. Third');

// Output (always in order):
// 1. First
// 2. Second
// 3. Third

// This is simple. But what if line 2 takes 5 seconds?
// EVERYTHING stops and waits.

function slowCalculation() {
  // Simulating a slow operation with a loop
  let total = 0;
  for (let i = 0; i < 2_000_000_000; i++) {
    total += i;
  }
  return total;
}

console.log('Starting calculation...');
const result = slowCalculation(); // ⚠️ The ENTIRE page freezes here!
console.log('Done:', result);      // Only runs after the loop finishes
console.log('This waits too!');    // Also blocked

// If this ran in a browser, you couldn't scroll, click, or
// interact with ANYTHING during those seconds. 😱

console.log('1. Start');

// setTimeout is asynchronous — it schedules code for later
setTimeout(() => {
  console.log('2. This runs LATER (after 2 seconds)');
}, 2000);

console.log('3. End');

// Output:
// 1. Start
// 3. End
// (2 seconds later...)
// 2. This runs LATER (after 2 seconds)

// 😲 Wait, '3. End' printed BEFORE '2. This runs LATER'!
// That's async in action:
// - JavaScript sees setTimeout, sends it to the browser's timer
// - Immediately moves to the next line (console.log '3. End')
// - 2 seconds later, the timer fires and the callback runs

// 1. Timers (setTimeout, setInterval)
setTimeout(() => console.log('Timer done!'), 1000);

// 2. Network requests (fetch) — most important!
// fetch('https://api.example.com/data')
//   .then(response => response.json())
//   .then(data => console.log(data));

// 3. Event listeners (click, keydown, etc.)
// button.addEventListener('click', () => console.log('Clicked!'));

// 4. Reading files (Node.js)
// fs.readFile('data.txt', (err, data) => console.log(data));

// 5. Geolocation
// navigator.geolocation.getCurrentPosition(pos => console.log(pos));

// 6. Animations
// requestAnimationFrame(() => console.log('Next frame!'));

// ALL of these are asynchronous:
// JavaScript starts them, then moves on.
// When they complete, a callback function runs.

// The pattern is always the same:
// 1. Start an async operation
// 2. Provide a callback (function to run when done)
// 3. JavaScript continues with other code
// 4. When the operation finishes, the callback runs

