function greet(name) {
  const message = createMessage(name); // Step 2: Push createMessage
  console.log(message);                // Step 4: Push console.log, run, pop
}                                       // Step 5: greet returns, pop

function createMessage(name) {
  return `Hello, ${name}!`;             // Step 3: Returns, pop createMessage
}

greet('Alice'); // Step 1: Push greet onto stack

// Call Stack trace:
// Step 1: [greet]
// Step 2: [greet, createMessage]
// Step 3: [greet]              ← createMessage returned, popped
// Step 4: [greet, console.log]
// Step 5: [greet]              ← console.log done, popped
// Step 6: []                   ← greet done, popped (stack empty!)

console.log('1. Script start');          // SYNC — runs immediately

setTimeout(() => {
  console.log('2. setTimeout');           // MACRO — goes to macrotask queue
}, 0);

Promise.resolve().then(() => {
  console.log('3. Promise');              // MICRO — goes to microtask queue
});

console.log('4. Script end');            // SYNC — runs immediately

// Output:
// 1. Script start
// 4. Script end
// 3. Promise          ← Microtask runs BEFORE macrotask!
// 2. setTimeout       ← Macrotask runs last

// WHY? Let's trace the event loop:
//
// 1. Call stack: console.log('1. Script start') → logs '1. Script start'
// 2. Call stack: setTimeout(...) → sends callback to Web API timer
//    Timer completes instantly (0ms) → callback → MACROTASK QUEUE
// 3. Call stack: Promise.resolve().then(...) → callback → MICROTASK QUEUE
// 4. Call stack: console.log('4. Script end') → logs '4. Script end'
// 5. Call stack is EMPTY! Event loop checks:
//    a. Any microtasks? YES → run Promise callback → logs '3. Promise'
//    b. Any more microtasks? NO
//    c. Any macrotasks? YES → run setTimeout callback → logs '2. setTimeout'

console.log('A');

setTimeout(() => {
  console.log('B');
  Promise.resolve().then(() => console.log('C'));
}, 0);

Promise.resolve().then(() => {
  console.log('D');
  setTimeout(() => console.log('E'), 0);
});

Promise.resolve().then(() => console.log('F'));

console.log('G');

// Output: A, G, D, F, B, C, E
//
// Step-by-step:
// 1. SYNC: log 'A'
// 2. setTimeout callback → macrotask queue
// 3. Promise callback (D + setTimeout) → microtask queue
// 4. Promise callback (F) → microtask queue
// 5. SYNC: log 'G'
// --- Stack empty, process microtasks ---
// 6. MICRO: log 'D', then schedule setTimeout(E) → macrotask queue
// 7. MICRO: log 'F'
// --- All microtasks done, process one macrotask ---
// 8. MACRO: log 'B', then Promise(C) → microtask queue
// --- Process new microtasks ---
// 9. MICRO: log 'C'
// --- Process next macrotask ---
// 10. MACRO: log 'E'

sections.content:
If you run a massive synchronous loop, the event loop can't process any callbacks:

javascript
setTimeout(() => console.log('I will be VERY late!'), 100);

// This blocks for ~5 seconds:
const start = Date.now();
while (Date.now() - start < 5000) {
  // Blocking the thread...
}

console.log('Loop done!');
// Output (after 5 seconds):
// 'Loop done!'
// 'I will be VERY late!'  ← Supposed to fire at 100ms, but waited 5000ms!


**Never block the main thread** with long-running synchronous operations. Use Web Workers for CPU-heavy tasks, or break work into chunks with setTimeout/requestAnimationFrame.

