// Basic syntax: setTimeout(callback, delayInMs)

// Run once after 2 seconds
setTimeout(() => {
  console.log('⏰ 2 seconds have passed!');
}, 2000);

// With a named function
function showNotification() {
  console.log('🔔 You have a new message!');
}
setTimeout(showNotification, 5000); // Shows after 5 seconds

// Passing arguments to the callback
function greet(name, emoji) {
  console.log(`${emoji} Hello, ${name}!`);
}
setTimeout(greet, 1000, 'Alice', '👋');
// After 1 second: "👋 Hello, Alice!"
// Note: arguments to greet go AFTER the delay

// ⚠️ Common mistake: calling the function instead of passing it
setTimeout(greet('Bob', '👋'), 1000);
// ❌ This calls greet IMMEDIATELY and passes its return value (undefined)
// ✅ Correct: setTimeout(greet, 1000, 'Bob', '👋')
// ✅ Or: setTimeout(() => greet('Bob', '👋'), 1000)

// setTimeout returns a timer ID that you can use to cancel it
const timerId = setTimeout(() => {
  console.log('This will never run!');
}, 5000);

console.log('Timer ID:', timerId); // A number like 1, 2, 3...

// Cancel it before it fires!
clearTimeout(timerId);
console.log('Timer cancelled! ❌');

// Practical example: Auto-save with cancel
let autoSaveTimer = null;

function scheduleAutoSave() {
  // Cancel any existing timer
  if (autoSaveTimer) {
    clearTimeout(autoSaveTimer);
  }

  // Schedule a new save in 3 seconds
  autoSaveTimer = setTimeout(() => {
    console.log('💾 Auto-saving...');
    // saveDocument();
    autoSaveTimer = null;
  }, 3000);

  console.log('Auto-save scheduled in 3 seconds...');
}

// Every time the user types, reset the timer
// This way, saving only happens 3 seconds AFTER they stop typing
scheduleAutoSave(); // Schedules save
scheduleAutoSave(); // Cancels previous, reschedules
scheduleAutoSave(); // Cancels previous, reschedules
// Only ONE save happens — 3 seconds after the last call
// This pattern is called 'debouncing'!

// setInterval runs a callback repeatedly at a fixed interval

// Update a clock every second
const clockTimer = setInterval(() => {
  const now = new Date();
  const time = now.toLocaleTimeString();
  console.log(`🕐 ${time}`);
}, 1000);

// Stop after 5 seconds
setTimeout(() => {
  clearInterval(clockTimer);
  console.log('⏹️ Clock stopped!');
}, 5000);

// Countdown timer
function startCountdown(seconds) {
  let remaining = seconds;

  console.log(`⏳ Countdown: ${remaining}`);

  const intervalId = setInterval(() => {
    remaining--;

    if (remaining <= 0) {
      clearInterval(intervalId); // Stop the interval!
      console.log('🎉 TIME\'S UP!');
    } else {
      console.log(`⏳ Countdown: ${remaining}`);
    }
  }, 1000);

  return intervalId; // Return ID in case caller wants to cancel
}

startCountdown(5);
// ⏳ Countdown: 5
// ⏳ Countdown: 4
// ⏳ Countdown: 3
// ⏳ Countdown: 2
// ⏳ Countdown: 1
// 🎉 TIME'S UP!

sections.content:
⚠️ **Problem 1: Intervals can stack up**
If the callback takes longer than the interval, calls can overlap:
javascript
setInterval(() => {
  // This takes 2 seconds...
  heavyWork();
}, 1000); // But interval is every 1 second!
// Callbacks pile up! 💀


⚠️ **Problem 2: Drift over time**
setInterval isn't perfectly precise. Each call has slight timing variations that add up.

✅ **Better alternative: recursive setTimeout**
javascript
function tick() {
  doWork();
  setTimeout(tick, 1000); // Schedule NEXT tick after work completes
}
tick();

This ensures each call starts AFTER the previous one finishes. No overlap, no stacking.

sections.code:
// DEBOUNCE: Wait until user STOPS doing something
// Use case: Search input — don't search on every keystroke
function debounce(func, delay) {
  let timerId;

  return function(...args) {
    clearTimeout(timerId); // Cancel previous timer
    timerId = setTimeout(() => {
      func.apply(this, args); // Run after user stops
    }, delay);
  };
}

// Usage:
const searchInput = document.querySelector('#search');
const debouncedSearch = debounce((query) => {
  console.log(`🔍 Searching for: ${query}`);
  // fetch(`/api/search?q=${query}`)...
}, 300);

// searchInput.addEventListener('input', (e) => {
//   debouncedSearch(e.target.value);
// });
// User types: "hello" rapidly
// Without debounce: 5 API calls (h, he, hel, hell, hello)
// With debounce: 1 API call (hello) — 300ms after last keystroke


// THROTTLE: Run at most once per time period
// Use case: Scroll handler — don't fire on every pixel
function throttle(func, limit) {
  let inThrottle = false;

  return function(...args) {
    if (!inThrottle) {
      func.apply(this, args);
      inThrottle = true;
      setTimeout(() => {
        inThrottle = false;
      }, limit);
    }
  };
}

// Usage:
const throttledScroll = throttle(() => {
  console.log('📜 Scroll position:', window.scrollY);
}, 200);

// window.addEventListener('scroll', throttledScroll);
// Without throttle: fires ~60 times per second while scrolling
// With throttle: fires at most 5 times per second (every 200ms)

