// Build a simple stopwatch using setInterval
let seconds = 0;
let timerId = null;

function start() {
  if (timerId) return; // Already running
  timerId = setInterval(() => {
    seconds++;
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    console.log(`⏱️ ${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`);
  }, 1000);
  console.log('▶️ Started!');
}

function stop() {
  clearInterval(timerId);
  timerId = null;
  console.log('⏸️ Stopped!');
}

function reset() {
  stop();
  seconds = 0;
  console.log('🔄 Reset! 00:00');
}

// Try it:
start();
// Wait a few seconds, then:
// stop();
// reset();

