// Simulating async operations (like API calls, file reads, etc.)

function getUserFromDatabase(userId, callback) {
  console.log(`📡 Fetching user ${userId} from database...`);

  // Simulate network delay with setTimeout
  setTimeout(() => {
    // Pretend we got data from a server
    const user = {
      id: userId,
      name: 'Alice Johnson',
      email: 'alice@example.com'
    };

    callback(user); // 📞 "Call back" with the result!
  }, 1500);
}

// Usage: pass a function to handle the result
getUserFromDatabase(42, (user) => {
  console.log('✅ Got user:', user.name);
  console.log('📧 Email:', user.email);
});

console.log('⏳ Waiting for database response...');

// Output:
// 📡 Fetching user 42 from database...
// ⏳ Waiting for database response...
// (1.5 seconds later)
// ✅ Got user: Alice Johnson
// 📧 Email: alice@example.com

// The Node.js convention: callback(error, result)
// If error is null/undefined, the operation succeeded
// If error has a value, something went wrong

function readUserFile(filename, callback) {
  console.log(`📁 Reading ${filename}...`);

  setTimeout(() => {
    // Simulate success or failure
    if (filename === 'missing.txt') {
      // Error case: first argument is the error
      callback(new Error(`File not found: ${filename}`), null);
    } else {
      // Success case: first argument is null (no error)
      const data = `Contents of ${filename}: Hello World!`;
      callback(null, data);
    }
  }, 1000);
}

// Usage: always check for errors first!
readUserFile('data.txt', (error, data) => {
  if (error) {
    console.error('❌ Error:', error.message);
    return;
  }
  console.log('✅ Success:', data);
});

readUserFile('missing.txt', (error, data) => {
  if (error) {
    console.error('❌ Error:', error.message);
    return;
  }
  console.log('✅ Success:', data);
});

// Output:
// 📁 Reading data.txt...
// 📁 Reading missing.txt...
// (1 second later)
// ✅ Success: Contents of data.txt: Hello World!
// ❌ Error: File not found: missing.txt

// What happens when you need to chain multiple async operations?
// Each one depends on the result of the previous one.

// Scenario: Get user → Get their orders → Get order details → Get shipping status

function getUser(userId, callback) {
  setTimeout(() => callback(null, { id: userId, name: 'Alice' }), 500);
}

function getOrders(userId, callback) {
  setTimeout(() => callback(null, [{ id: 101, item: 'Laptop' }]), 500);
}

function getOrderDetails(orderId, callback) {
  setTimeout(() => callback(null, { id: orderId, total: 999, shipped: true }), 500);
}

function getShippingStatus(orderId, callback) {
  setTimeout(() => callback(null, { status: 'Delivered', date: '2024-01-15' }), 500);
}

// 😱 CALLBACK HELL — The Pyramid of Doom!
getUser(42, (err, user) => {
  if (err) { console.error(err); return; }
  console.log('Got user:', user.name);

  getOrders(user.id, (err, orders) => {
    if (err) { console.error(err); return; }
    console.log('Got orders:', orders.length);

    getOrderDetails(orders[0].id, (err, details) => {
      if (err) { console.error(err); return; }
      console.log('Order total:', details.total);

      getShippingStatus(orders[0].id, (err, shipping) => {
        if (err) { console.error(err); return; }
        console.log('Shipping:', shipping.status);

        // Need MORE nested operations? It keeps going deeper...
        // 👉 Imagine 10 levels of this nesting! 🤯
      });
    });
  });
});

// Problems with callback hell:
// 1. Code moves RIGHT instead of DOWN (hard to read)
// 2. Error handling is repetitive (if (err) on every level)
// 3. Hard to debug — which level caused the bug?
// 4. Extremely difficult to add features or modify
// 5. Can't easily run operations in parallel
// 6. Variable scoping becomes confusing

sections.content:
Callback Hell (Pyramid of Doom):

getUser(id, (err, user) => {
    |
    └──> getOrders(user.id, (err, orders) => {
            |
            └──> getOrderDetails(orders[0].id, (err, details) => {
                    |
                    └──> getShippingStatus(id, (err, status) => {
                            |
                            └──> // MORE NESTING... 😱
                         });
                 });
         });
});


With Promises (flat chain — preview of next lesson!):

getUser(id)
  .then(user => getOrders(user.id))
  .then(orders => getOrderDetails(orders[0].id))
  .then(details => getShippingStatus(details.id))
  .then(status => console.log(status))
  .catch(err => console.error(err));  // ONE error handler for all!

// Same logic, completely flat, much easier to read! 😍

