// The Promise constructor takes a function with two parameters:
// resolve — call this when the operation SUCCEEDS
// reject — call this when the operation FAILS

const myPromise = new Promise((resolve, reject) => {
  // Simulate an async operation
  console.log('⏳ Starting async operation...');

  setTimeout(() => {
    const success = true; // Toggle this to see both outcomes

    if (success) {
      resolve('Here is your data! 📦');  // ✅ Fulfilled!
    } else {
      reject(new Error('Something went wrong! 💥')); // ❌ Rejected!
    }
  }, 2000);
});

console.log('Promise created:', myPromise); // Promise { <pending> }

// Handle the result with .then() and .catch()
myPromise
  .then((value) => {
    console.log('✅ Success:', value);
  })
  .catch((error) => {
    console.error('❌ Error:', error.message);
  });

console.log('⏳ Waiting for promise to settle...');

// Output:
// ⏳ Starting async operation...
// Promise created: Promise { <pending> }
// ⏳ Waiting for promise to settle...
// (2 seconds later)
// ✅ Success: Here is your data! 📦

// Wrapping setTimeout in a Promise — a clean 'wait' function
function wait(ms) {
  return new Promise((resolve) => {
    setTimeout(resolve, ms);
  });
}

// Usage:
wait(2000).then(() => {
  console.log('⏰ 2 seconds have passed!');
});

// Simulating an API call
function fetchUser(userId) {
  return new Promise((resolve, reject) => {
    console.log(`📡 Fetching user ${userId}...`);

    setTimeout(() => {
      if (userId <= 0) {
        reject(new Error('Invalid user ID'));
        return;
      }

      const users = {
        1: { id: 1, name: 'Alice', role: 'admin' },
        2: { id: 2, name: 'Bob', role: 'user' },
        3: { id: 3, name: 'Carol', role: 'user' },
      };

      const user = users[userId];

      if (user) {
        resolve(user); // ✅ Found the user!
      } else {
        reject(new Error(`User ${userId} not found`)); // ❌ Not found
      }
    }, 1000);
  });
}

// Usage — clean and readable!
fetchUser(1)
  .then((user) => {
    console.log('✅ Found:', user.name, `(${user.role})`);
  })
  .catch((error) => {
    console.error('❌', error.message);
  });

fetchUser(999)
  .then((user) => {
    console.log('✅ Found:', user.name);
  })
  .catch((error) => {
    console.error('❌', error.message); // ❌ User 999 not found
  });

// Original callback-based function
function getDataCallback(id, callback) {
  setTimeout(() => {
    if (id < 0) {
      callback(new Error('Invalid ID'), null);
    } else {
      callback(null, { id, value: 'Some data' });
    }
  }, 1000);
}

// Convert it to return a Promise!
function getData(id) {
  return new Promise((resolve, reject) => {
    getDataCallback(id, (error, data) => {
      if (error) {
        reject(error);   // Route error to .catch()
      } else {
        resolve(data);   // Route success to .then()
      }
    });
  });
}

// Now we can use it with Promises!
getData(42)
  .then(data => console.log('✅ Got:', data))
  .catch(err => console.error('❌', err.message));

// A generic promisify utility
function promisify(fn) {
  return function(...args) {
    return new Promise((resolve, reject) => {
      fn(...args, (error, result) => {
        if (error) reject(error);
        else resolve(result);
      });
    });
  };
}

// Usage:
const getDataPromise = promisify(getDataCallback);
getDataPromise(42)
  .then(data => console.log('✅', data))
  .catch(err => console.error('❌', err.message));

