// Same scenario as callback hell: User → Orders → Details → Shipping
// But now with Promises — completely flat!

function getUser(userId) {
  return new Promise((resolve) => {
    setTimeout(() => resolve({ id: userId, name: 'Alice' }), 500);
  });
}

function getOrders(userId) {
  return new Promise((resolve) => {
    setTimeout(() => resolve([{ id: 101, item: 'Laptop', userId }]), 500);
  });
}

function getOrderDetails(orderId) {
  return new Promise((resolve) => {
    setTimeout(() => resolve({ id: orderId, total: 999, shipped: true }), 500);
  });
}

function getShippingStatus(orderId) {
  return new Promise((resolve) => {
    setTimeout(() => resolve({ status: 'Delivered', date: '2024-01-15' }), 500);
  });
}

// 🎉 Promise chain — FLAT, not nested!
getUser(42)
  .then(user => {
    console.log('👤 User:', user.name);
    return getOrders(user.id);          // Return a Promise → next .then waits for it
  })
  .then(orders => {
    console.log('📦 Orders:', orders.length);
    return getOrderDetails(orders[0].id); // Return a Promise
  })
  .then(details => {
    console.log('💰 Total: $' + details.total);
    return getShippingStatus(details.id); // Return a Promise
  })
  .then(shipping => {
    console.log('🚚 Status:', shipping.status);
    console.log('📅 Date:', shipping.date);
  })
  .catch(error => {
    // ONE catch handles errors from ANY step! 🎯
    console.error('❌ Error:', error.message);
  });

// Compare this to callback hell — same logic, night and day difference!

// Values flow through the chain like water through pipes

Promise.resolve(1)
  .then(value => {
    console.log(value);        // 1
    return value + 10;         // Return a regular value
  })
  .then(value => {
    console.log(value);        // 11
    return value * 2;          // Return another value
  })
  .then(value => {
    console.log(value);        // 22
    return Promise.resolve(value + 100); // Return a Promise
  })
  .then(value => {
    console.log(value);        // 122 (Promise unwrapped automatically!)
  });

// ⚠️ Common mistake: forgetting to return!
Promise.resolve('hello')
  .then(value => {
    console.log(value);       // 'hello'
    value.toUpperCase();      // ❌ No return! Result is lost!
  })
  .then(value => {
    console.log(value);       // undefined — because nothing was returned!
  });

// ✅ Fix: always return!
Promise.resolve('hello')
  .then(value => {
    console.log(value);       // 'hello'
    return value.toUpperCase(); // ✅ Return the result!
  })
  .then(value => {
    console.log(value);       // 'HELLO' ✅
  });

// Errors propagate DOWN the chain until they hit a .catch()

function riskyStep(stepNumber) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (stepNumber === 3) {
        reject(new Error(`Step ${stepNumber} failed! 💥`));
      } else {
        resolve(`Step ${stepNumber} OK ✅`);
      }
    }, 300);
  });
}

riskyStep(1)
  .then(result => {
    console.log(result);       // Step 1 OK ✅
    return riskyStep(2);
  })
  .then(result => {
    console.log(result);       // Step 2 OK ✅
    return riskyStep(3);       // 💥 This one fails!
  })
  .then(result => {
    console.log(result);       // ⏩ SKIPPED! Error jumped to .catch()
    return riskyStep(4);
  })
  .then(result => {
    console.log(result);       // ⏩ SKIPPED! Still in error state
  })
  .catch(error => {
    console.error('💥 Caught:', error.message); // Step 3 failed! 💥
    // The chain can continue after .catch()!
    return 'Recovered! 🔧';
  })
  .then(value => {
    console.log(value);        // 'Recovered! 🔧' — chain continues!
  });

// Key insight: .catch() is like a try/catch for the entire chain.
// Errors skip all .then() calls and go straight to .catch().
// After .catch(), the chain can continue with the recovered value!

// .finally() runs regardless of success or failure
// Perfect for cleanup: hiding loading spinners, closing connections, etc.

function fetchDataFromAPI() {
  console.log('🔄 Loading...');
  // showLoadingSpinner();

  return fetchUser(1)
    .then(user => {
      console.log('✅ Got user:', user.name);
      return user;
    })
    .catch(error => {
      console.error('❌ Failed:', error.message);
      return null; // Return null so the app doesn't crash
    })
    .finally(() => {
      // This runs NO MATTER WHAT — success or failure!
      console.log('🏁 Done! (hiding spinner)');
      // hideLoadingSpinner();
    });
}

// Real-world pattern:
function saveToDatabase(data) {
  let connection;

  return openConnection()
    .then(conn => {
      connection = conn;
      return conn.save(data);
    })
    .then(() => console.log('✅ Saved!'))
    .catch(err => console.error('❌ Save failed:', err.message))
    .finally(() => {
      // ALWAYS close the connection, even if saving failed
      if (connection) connection.close();
      console.log('🔌 Connection closed.');
    });
}

