// Helper: simulates fetching a user from a database
function fetchUser(id) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (id <= 0) reject(new Error('Invalid ID'));
      else resolve({ id, name: 'Alice', email: 'alice@example.com' });
    }, 1000);
  });
}

// ========= PROMISE CHAIN VERSION =========
function getUserDataChain() {
  return fetchUser(1)
    .then(user => {
      console.log('Got user:', user.name);
      return user;
    })
    .catch(error => {
      console.error('Error:', error.message);
    });
}

// ========= ASYNC/AWAIT VERSION =========
async function getUserDataAsync() {
  try {
    const user = await fetchUser(1);  // ⏸️ Pause here until Promise resolves
    console.log('Got user:', user.name);
    return user;
  } catch (error) {
    console.error('Error:', error.message);
  }
}

// Both do EXACTLY the same thing!
// But the async/await version reads like synchronous code.
// No .then(), no .catch() — just const result = await asyncOperation();

getUserDataAsync();

// The same User → Orders → Details → Shipping flow
// Compare with the Promise chain version!

async function getFullOrderInfo(userId) {
  try {
    // Each await pauses until the previous operation completes
    const user = await getUser(userId);
    console.log('👤 User:', user.name);

    const orders = await getOrders(user.id);
    console.log('📦 Orders:', orders.length);

    const details = await getOrderDetails(orders[0].id);
    console.log('💰 Total: $' + details.total);

    const shipping = await getShippingStatus(details.id);
    console.log('🚚 Status:', shipping.status);
    console.log('📅 Date:', shipping.date);

    return shipping; // Returned value becomes the Promise's resolved value

  } catch (error) {
    // ONE catch block handles errors from ANY await above!
    console.error('❌ Error:', error.message);
    return null;
  } finally {
    console.log('🏁 Done!');
  }
}

// Call it — returns a Promise!
getFullOrderInfo(42).then(result => {
  console.log('Final result:', result);
});

// Or call from another async function:
async function main() {
  const result = await getFullOrderInfo(42);
  console.log('Final result:', result);
}
main();

// async/await shines when you have complex control flow!

async function processUsers(userIds) {
  const results = [];

  for (const id of userIds) {
    try {
      const user = await fetchUser(id);

      // Conditional logic — simple and natural!
      if (user.role === 'admin') {
        console.log(`👑 Admin found: ${user.name}`);
        const adminData = await getAdminDashboard(user.id);
        results.push({ ...user, dashboard: adminData });
      } else {
        console.log(`👤 Regular user: ${user.name}`);
        results.push(user);
      }

    } catch (error) {
      console.warn(`⚠️ Skipping user ${id}: ${error.message}`);
      // Continue to next user instead of stopping
    }
  }

  return results;
}

// Try doing this with Promise chains — it's a nightmare! 😱
// With async/await, it's just a regular for loop with if/else.

// Arrow function version:
const fetchAndLog = async (id) => {
  const user = await fetchUser(id);
  console.log(user.name);
  return user;
};

// IIFE (Immediately Invoked Function Expression) for top-level await
(async () => {
  const users = await processUsers([1, 2, 3]);
  console.log('All processed:', users.length);
})();

// Even if you return a plain value, it's wrapped in a Promise
async function getNumber() {
  return 42;
}

// getNumber() returns Promise<42>, not just 42
const result = getNumber();
console.log(result); // Promise { 42 }

// To get the actual value:
getNumber().then(num => console.log(num)); // 42
// Or:
async function main() {
  const num = await getNumber();
  console.log(num); // 42
}

// If the async function throws, the Promise is rejected
async function willFail() {
  throw new Error('Oops!');
}

willFail().catch(err => console.error(err.message)); // 'Oops!'

// This is equivalent to:
function willFailPromise() {
  return Promise.reject(new Error('Oops!'));
}

