// Simulated async functions
function fetchProfile(userId) {
  return new Promise(resolve => {
    setTimeout(() => resolve({ name: 'Alice', bio: 'Developer' }), 1000);
  });
}

function fetchPosts(userId) {
  return new Promise(resolve => {
    setTimeout(() => resolve(['Post 1', 'Post 2', 'Post 3']), 1200);
  });
}

function fetchNotifications(userId) {
  return new Promise(resolve => {
    setTimeout(() => resolve([{ text: 'New follower' }]), 800);
  });
}

// ❌ SEQUENTIAL — slow!
async function loadDashboardSlow(userId) {
  console.time('Sequential');
  const profile = await fetchProfile(userId);        // Wait 1s
  const posts = await fetchPosts(userId);            // Wait 1.2s more
  const notifications = await fetchNotifications(userId); // Wait 0.8s more
  console.timeEnd('Sequential'); // Total: ~3 seconds! 😴
  return { profile, posts, notifications };
}

// ✅ PARALLEL with Promise.all — fast!
async function loadDashboardFast(userId) {
  console.time('Parallel');
  const [profile, posts, notifications] = await Promise.all([
    fetchProfile(userId),        // Starts immediately
    fetchPosts(userId),          // Starts immediately
    fetchNotifications(userId),  // Starts immediately
  ]);
  console.timeEnd('Parallel'); // Total: ~1.2 seconds! ⚡
  return { profile, posts, notifications };
}

// Promise.all:
// - Takes an ARRAY of Promises
// - Returns a Promise that resolves with an ARRAY of results
// - Results are in the SAME ORDER as the input (not completion order)
// - If ANY one fails, the entire Promise.all rejects!

loadDashboardFast(1).then(data => {
  console.log('Profile:', data.profile.name);
  console.log('Posts:', data.posts.length);
  console.log('Notifications:', data.notifications.length);
});

// ⚠️ IMPORTANT: If ANY Promise rejects, Promise.all rejects!

const results = Promise.all([
  Promise.resolve('A'),
  Promise.reject(new Error('B failed!')),  // 💥 One failure!
  Promise.resolve('C'),
]);

results
  .then(values => console.log('All succeeded:', values))
  .catch(error => console.error('One failed:', error.message));

// Output: "One failed: B failed!"
// Even though A and C succeeded, we get NOTHING!

// This is "all or nothing" behavior.
// If you need results from the successful ones, use Promise.allSettled()

// Promise.allSettled waits for ALL Promises, regardless of outcome
// It NEVER rejects — it always resolves with an array of result objects

const results = await Promise.allSettled([
  fetchProfile(1),                          // ✅ Succeeds
  Promise.reject(new Error('Posts error')), // ❌ Fails
  fetchNotifications(1),                     // ✅ Succeeds
]);

console.log(results);
// [
//   { status: 'fulfilled', value: { name: 'Alice', bio: 'Developer' } },
//   { status: 'rejected',  reason: Error: Posts error },
//   { status: 'fulfilled', value: [{ text: 'New follower' }] }
// ]

// Process results — handle each independently
results.forEach((result, index) => {
  if (result.status === 'fulfilled') {
    console.log(`✅ Request ${index}: ${JSON.stringify(result.value)}`);
  } else {
    console.warn(`❌ Request ${index}: ${result.reason.message}`);
  }
});

// Extract only successful results
const successfulResults = results
  .filter(r => r.status === 'fulfilled')
  .map(r => r.value);

console.log('Successful:', successfulResults);

// Promise.race resolves/rejects as soon as the FIRST Promise settles

// Practical: Timeout pattern!
function fetchWithTimeout(url, timeoutMs) {
  const fetchPromise = fetch(url);  // Real network request

  const timeoutPromise = new Promise((_, reject) => {
    setTimeout(() => {
      reject(new Error(`Request timed out after ${timeoutMs}ms`));
    }, timeoutMs);
  });

  // Whichever finishes first wins!
  return Promise.race([fetchPromise, timeoutPromise]);
}

// Usage:
// fetchWithTimeout('https://api.example.com/data', 5000)
//   .then(response => console.log('Got response!'))
//   .catch(error => console.error(error.message));
// If the fetch takes more than 5 seconds, we get a timeout error!

// Simulated race example:
const fast = new Promise(resolve => setTimeout(() => resolve('🐇 Fast!'), 500));
const slow = new Promise(resolve => setTimeout(() => resolve('🐢 Slow!'), 2000));

Promise.race([fast, slow]).then(winner => {
  console.log('Winner:', winner); // '🐇 Fast!' (after 500ms)
  // The slow Promise still completes, but its result is ignored
});

// Promise.any resolves with the first FULFILLED Promise
// It ignores rejections unless ALL Promises reject

// Use case: Try multiple mirrors/CDNs, use whichever responds first
async function fetchFromFastestMirror(url) {
  const mirrors = [
    `https://mirror1.cdn.com${url}`,
    `https://mirror2.cdn.com${url}`,
    `https://mirror3.cdn.com${url}`,
  ];

  try {
    const data = await Promise.any(
      mirrors.map(mirror => 
        fetch(mirror).then(r => r.json())
      )
    );
    return data; // First successful response!
  } catch (error) {
    // AggregateError — ALL mirrors failed!
    console.error('All mirrors failed:', error.errors);
    throw error;
  }
}

// Simple example:
const p1 = Promise.reject('❌ A failed');
const p2 = new Promise(resolve => setTimeout(() => resolve('✅ B succeeded!'), 200));
const p3 = Promise.reject('❌ C failed');

Promise.any([p1, p2, p3])
  .then(value => console.log('First success:', value)) // '✅ B succeeded!'
  .catch(error => console.error('All failed!', error));

