// Simulates real API calls with realistic timing and occasional failures

class APISimulator {
  static #responseTime() {
    return 500 + Math.floor(Math.random() * 1500); // 500-2000ms
  }

  static fetchUser(userId) {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        if (Math.random() < 0.1) { // 10% failure rate
          reject(new Error(`Network error fetching user ${userId}`));
          return;
        }
        const users = {
          1: { id: 1, name: 'Alice Chen', department: 'Engineering' },
          2: { id: 2, name: 'Bob Martinez', department: 'Design' },
          3: { id: 3, name: 'Carol Williams', department: 'Marketing' },
          4: { id: 4, name: 'David Kim', department: 'Engineering' },
          5: { id: 5, name: 'Eva Brown', department: 'Design' },
        };
        const user = users[userId];
        if (!user) reject(new Error(`User ${userId} not found`));
        else resolve(user);
      }, this.#responseTime());
    });
  }

  static fetchUserPosts(userId) {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        if (Math.random() < 0.15) {
          reject(new Error(`Failed to load posts for user ${userId}`));
          return;
        }
        const posts = Array.from({ length: Math.floor(Math.random() * 5) + 1 }, (_, i) => ({
          id: userId * 100 + i,
          title: `Post ${i + 1} by User ${userId}`,
          likes: Math.floor(Math.random() * 100),
        }));
        resolve(posts);
      }, this.#responseTime());
    });
  }

  static fetchUserStats(userId) {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        if (Math.random() < 0.1) {
          reject(new Error(`Stats unavailable for user ${userId}`));
          return;
        }
        resolve({
          userId,
          followers: Math.floor(Math.random() * 1000),
          following: Math.floor(Math.random() * 500),
          totalLikes: Math.floor(Math.random() * 5000),
        });
      }, this.#responseTime());
    });
  }

  static fetchWeather(city) {
    return new Promise((resolve) => {
      setTimeout(() => {
        const conditions = ['Sunny ☀️', 'Cloudy ☁️', 'Rainy 🌧️', 'Snowy ❄️'];
        resolve({
          city,
          temp: Math.floor(Math.random() * 35) + 5,
          condition: conditions[Math.floor(Math.random() * conditions.length)],
        });
      }, this.#responseTime());
    });
  }
}

// These are realistic simulations:
// - Random response times (500-2000ms)
// - Occasional failures (10-15% failure rate)
// - Realistic data shapes
// Your code must handle ALL of this gracefully!

// A function that retries a failed operation up to N times
async function withRetry(operation, maxRetries = 3, delayMs = 500) {
  let lastError;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const result = await operation();
      if (attempt > 1) {
        console.log(`  ✅ Succeeded on attempt ${attempt}`);
      }
      return result;
    } catch (error) {
      lastError = error;
      console.warn(`  ⚠️ Attempt ${attempt}/${maxRetries} failed: ${error.message}`);

      if (attempt < maxRetries) {
        // Wait before retrying (exponential backoff)
        const waitTime = delayMs * Math.pow(2, attempt - 1);
        console.log(`  ⏳ Retrying in ${waitTime}ms...`);
        await new Promise(resolve => setTimeout(resolve, waitTime));
      }
    }
  }

  throw new Error(`Failed after ${maxRetries} attempts: ${lastError.message}`);
}

// Usage:
async function fetchUserSafe(userId) {
  return withRetry(
    () => APISimulator.fetchUser(userId),
    3,     // Max 3 attempts
    500    // Start with 500ms delay, doubling each time
  );
}

// Test it:
async function testRetry() {
  try {
    const user = await fetchUserSafe(1);
    console.log('Got user:', user.name);
  } catch (error) {
    console.error('Gave up:', error.message);
  }
}
testRetry();

async function loadUserDashboard(userId) {
  console.log(`\n📊 Loading dashboard for user ${userId}...`);
  console.time('Dashboard load time');

  // Step 1: Fetch the user (required — fail if this fails)
  let user;
  try {
    user = await withRetry(() => APISimulator.fetchUser(userId));
    console.log(`👤 User loaded: ${user.name}`);
  } catch (error) {
    console.error(`❌ Critical failure: ${error.message}`);
    console.timeEnd('Dashboard load time');
    return null; // Can't proceed without the user
  }

  // Step 2: Fetch supplementary data IN PARALLEL (optional — use allSettled)
  const [postsResult, statsResult, weatherResult] = await Promise.allSettled([
    withRetry(() => APISimulator.fetchUserPosts(userId)),
    withRetry(() => APISimulator.fetchUserStats(userId)),
    APISimulator.fetchWeather('San Francisco'), // No retry for weather
  ]);

  // Step 3: Process results — handle successes and failures independently
  const dashboard = {
    user,
    posts: postsResult.status === 'fulfilled' ? postsResult.value : [],
    stats: statsResult.status === 'fulfilled' ? statsResult.value : null,
    weather: weatherResult.status === 'fulfilled' ? weatherResult.value : null,
  };

  // Step 4: Display the dashboard
  console.log('\n═══════════════════════════════════');
  console.log(`  📊 Dashboard for ${dashboard.user.name}`);
  console.log(`  🏢 Department: ${dashboard.user.department}`);
  console.log('───────────────────────────────────');

  if (dashboard.posts.length > 0) {
    console.log(`  📝 Posts: ${dashboard.posts.length}`);
    const topPost = dashboard.posts.reduce((a, b) => a.likes > b.likes ? a : b);
    console.log(`  🌟 Top post: "${topPost.title}" (${topPost.likes} likes)`);
  } else {
    console.log('  📝 Posts: Unable to load');
  }

  if (dashboard.stats) {
    console.log(`  👥 Followers: ${dashboard.stats.followers}`);
    console.log(`  ❤️ Total likes: ${dashboard.stats.totalLikes}`);
  } else {
    console.log('  📊 Stats: Unable to load');
  }

