// CHALLENGE: Build a TaskQueue class that:
// 1. Accepts tasks (functions that return Promises)
// 2. Has a 'concurrency' limit (max tasks running at once)
// 3. Processes tasks respecting the concurrency limit
// 4. Reports progress and results

class TaskQueue {
  #tasks;
  #concurrency;
  #running;
  #results;

  constructor(concurrency = 2) {
    this.#tasks = [];
    this.#concurrency = concurrency;
    this.#running = 0;
    this.#results = [];
  }

  add(taskFn, label = 'Task') {
    this.#tasks.push({ fn: taskFn, label });
    return this; // For chaining
  }

  async run() {
    // YOUR CHALLENGE:
    // Process all tasks with at most this.#concurrency running at once
    // Log when each task starts and finishes
    // Return an array of all results

    // Hint: Use a while loop and Promise.race to manage concurrency
    // Or process in batches with Promise.all

    console.log(`🚀 Running ${this.#tasks.length} tasks (concurrency: ${this.#concurrency})`);

    // Simple batch approach:
    const results = [];
    for (let i = 0; i < this.#tasks.length; i += this.#concurrency) {
      const batch = this.#tasks.slice(i, i + this.#concurrency);
      console.log(`\n📦 Batch: ${batch.map(t => t.label).join(', ')}`);

      const batchResults = await Promise.allSettled(
        batch.map(async (task) => {
          console.log(`  ▶️ Starting: ${task.label}`);
          const result = await task.fn();
          console.log(`  ✅ Finished: ${task.label}`);
          return result;
        })
      );

      results.push(...batchResults);
    }

    return results;
  }
}

// Test it!
const queue = new TaskQueue(2); // Max 2 concurrent tasks

queue
