javascript
// ❌ This looks correct but has a subtle bug!
try {
  const response = await fetch('https://api.example.com/nonexistent');
  const data = await response.json(); // Tries to parse a 404 error page!
  console.log(data); // Might crash or show garbage
} catch (error) {
  // This ONLY runs for network errors!
  // A 404 or 500 does NOT trigger this catch block!
  console.error(error);
}


**fetch() will NOT throw for:** 400, 401, 403, 404, 500, 503, etc.
**fetch() WILL throw for:** No internet, DNS failure, CORS blocked, server unreachable.

You MUST manually check `response.ok` to catch HTTP errors!

sections.code:
// ✅ CORRECT: Check response.ok AND catch network errors

async function fetchData(url) {
  try {
    const response = await fetch(url);

    // Check for HTTP errors (404, 500, etc.)
    if (!response.ok) {
      // Create a descriptive error
      throw new Error(
        `HTTP Error: ${response.status} ${response.statusText}`
      );
    }

    const data = await response.json();
    return data;

  } catch (error) {
    // This catches BOTH:
    // 1. Network errors (thrown by fetch itself)
    // 2. HTTP errors (thrown by our code above)
    // 3. JSON parsing errors (invalid JSON response)

    if (error.name === 'TypeError') {
      // Network error — no internet, server unreachable, CORS blocked
      console.error('🌐 Network error:', error.message);
    } else {
      // HTTP error or other error
      console.error('❌ Request failed:', error.message);
    }

    return null; // Return null so calling code can handle it
  }
}

// Usage:
async function loadUser(id) {
  const user = await fetchData(`https://jsonplaceholder.typicode.com/users/${id}`);

  if (user) {
    console.log('✅ Got user:', user.name);
  } else {
    console.log('❌ Failed to load user');
  }
}

loadUser(1);   // ✅ Works
loadUser(999); // ❌ HTTP Error: 404 Not Found

// A production-quality fetch wrapper you can reuse everywhere!

class APIError extends Error {
  constructor(status, statusText, data) {
    super(`HTTP ${status}: ${statusText}`);
    this.name = 'APIError';
    this.status = status;
    this.statusText = statusText;
    this.data = data; // Server's error response body
  }
}

async function apiFetch(url, options = {}) {
  const defaultHeaders = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  };

  const config = {
    ...options,
    headers: {
      ...defaultHeaders,
      ...options.headers,
    },
  };

  // Don't set Content-Type for GET/DELETE (no body)
  if (!options.body) {
    delete config.headers['Content-Type'];
  }

  let response;

  try {
    response = await fetch(url, config);
  } catch (networkError) {
    // True network failure — no response at all
    throw new Error(
      navigator.onLine
        ? `Network error: Could not reach ${new URL(url).hostname}`
        : 'You appear to be offline. Check your internet connection.'
    );
  }

  // HTTP error — server responded but with an error code
  if (!response.ok) {
    let errorData = null;
    try {
      errorData = await response.json(); // Try to get error details
    } catch {
      // Response body wasn't JSON — that's fine
    }
    throw new APIError(response.status, response.statusText, errorData);
  }

  // 204 No Content — successful but no body to parse
  if (response.status === 204) {
    return null;
  }

  return response.json();
}

// ============ USAGE ============

async function demo() {
  try {
    // GET
    const users = await apiFetch('https://jsonplaceholder.typicode.com/users');
    console.log('Users:', users.length);

    // POST
    const newPost = await apiFetch('https://jsonplaceholder.typicode.com/posts', {
      method: 'POST',
      body: JSON.stringify({
        title: 'Hello World',
        body: 'My first post!',
        userId: 1,
      }),
    });
    console.log('Created:', newPost.id);

  } catch (error) {
    if (error instanceof APIError) {
      // HTTP error — we can check the status code
      switch (error.status) {
        case 400: console.error('Bad request — check your data'); break;
        case 401: console.error('Not authorized — please log in'); break;
        case 404: console.error('Not found — resource doesn\'t exist'); break;
        case 429: console.error('Too many requests — slow down!'); break;
        case 500: console.error('Server error — try again later'); break;
        default:  console.error('API error:', error.message);
      }
    } else {
      // Network error or other unexpected error
      console.error('Error:', error.message);
    }
  }
}

demo();

// Map technical errors to human-readable messages
function getUserFriendlyMessage(error) {
  if (error instanceof APIError) {
    const messages = {
      400: 'Something was wrong with your request. Please check your input.',
      401: 'You need to log in to access this.',
      403: 'You don\'t have permission to do that.',
      404: 'The item you\'re looking for doesn\'t exist.',
      409: 'This conflicts with existing data. Try refreshing.',
      429: 'Too many requests. Please wait a moment and try again.',
      500: 'Something went wrong on our end. Please try again later.',
      503: 'The service is temporarily unavailable. Please try again later.',
    };
    return messages[error.status] || `An error occurred (${error.status}).`;
  }

  if (!navigator.onLine) {
    return 'You appear to be offline. Please check your internet connection.';
  }

  return 'Something went wrong. Please try again.';
}

// In your UI code:
async function loadProfile() {
  const container = document.querySelector('#profile');
  const errorBox = document.querySelector('#error-message');
  errorBox.classList.add('hidden');

  try {
    const user = await apiFetch('/api/profile');
    container.innerHTML = `<h2>${user.name}</h2><p>${user.email}</p>`;

  } catch (error) {
    const message = getUserFriendlyMessage(error);
    errorBox.textContent = message;
    errorBox.classList.remove('hidden');

    // Log the technical details for debugging
    console.error('Profile load failed:', error);
  }
}

sections.content:
Every API call in your UI should handle THREE states:

1. ⏳ **Loading** — Show a spinner, skeleton screen, or 'Loading...' text
2. ✅ **Success** — Display the data
3. ❌ **Error** — Show a user-friendly error message with a retry option

javascript
async function loadData() {
  showLoading();      // State 1: Loading
  try {
    const data = await apiFetch('/api/data');
    showData(data);   // State 2: Success
  } catch (error) {
    showError(error);  // State 3: Error
  }
}


Skipping any of these states creates a poor user experience.

