// Their geocoding API converts city names to coordinates.

class GeocodingService {
  static BASE_URL = 'https://geocoding-api.open-meteo.com/v1';

  static async searchCity(cityName) {
    const params = new URLSearchParams({
      name: cityName,
      count: 5,             // Return up to 5 results
      language: 'en',
      format: 'json',
    });

    const response = await fetch(`${this.BASE_URL}/search?${params}`);

    if (!response.ok) {
      throw new Error(`Geocoding API error: ${response.status}`);
    }

    const data = await response.json();

    if (!data.results || data.results.length === 0) {
      throw new Error(`City "${cityName}" not found. Try a different spelling.`);
    }

    // Return the best match
    return data.results.map(result => ({
      name: result.name,
      country: result.country,
      state: result.admin1 || '',
      latitude: result.latitude,
      longitude: result.longitude,
    }));
  }
}

