class WeatherService {
  static BASE_URL = 'https://api.open-meteo.com/v1';

  // Map weather codes to descriptions and emojis
  static WEATHER_CODES = {
    0: { description: 'Clear sky', emoji: '☀️' },
    1: { description: 'Mainly clear', emoji: '🌤️' },
    2: { description: 'Partly cloudy', emoji: '⛅' },
    3: { description: 'Overcast', emoji: '☁️' },
    45: { description: 'Foggy', emoji: '🌫️' },
    48: { description: 'Icy fog', emoji: '🌫️' },
    51: { description: 'Light drizzle', emoji: '🌦️' },
    53: { description: 'Moderate drizzle', emoji: '🌦️' },
    55: { description: 'Dense drizzle', emoji: '🌧️' },
    61: { description: 'Light rain', emoji: '🌧️' },
    63: { description: 'Moderate rain', emoji: '🌧️' },
    65: { description: 'Heavy rain', emoji: '🌧️' },
    71: { description: 'Light snow', emoji: '🌨️' },
    73: { description: 'Moderate snow', emoji: '🌨️' },
    75: { description: 'Heavy snow', emoji: '❄️' },
    80: { description: 'Rain showers', emoji: '🌦️' },
    95: { description: 'Thunderstorm', emoji: '⛈️' },
  };

  static getWeatherInfo(code) {
    return this.WEATHER_CODES[code] || { description: 'Unknown', emoji: '❓' };
  }

  static async getWeather(latitude, longitude) {
    const params = new URLSearchParams({
      latitude,
      longitude,
      current: 'temperature_2m,relative_humidity_2m,weather_code,wind_speed_10m',
      daily: 'weather_code,temperature_2m_max,temperature_2m_min',
      timezone: 'auto',
      forecast_days: '7',
    });

    const response = await fetch(`${this.BASE_URL}/forecast?${params}`);

    if (!response.ok) {
      throw new Error(`Weather API error: ${response.status}`);
    }

    const data = await response.json();

    // Transform the raw API data into a cleaner format
    const weatherInfo = this.getWeatherInfo(data.current.weather_code);

    return {
      current: {
        temperature: Math.round(data.current.temperature_2m),
        humidity: data.current.relative_humidity_2m,
        windSpeed: Math.round(data.current.wind_speed_10m),
        description: weatherInfo.description,
        emoji: weatherInfo.emoji,
      },
      forecast: data.daily.time.map((date, index) => {
        const dayWeather = this.getWeatherInfo(data.daily.weather_code[index]);
        return {
          date,
          dayName: new Date(date).toLocaleDateString('en', { weekday: 'short' }),
          maxTemp: Math.round(data.daily.temperature_2m_max[index]),
          minTemp: Math.round(data.daily.temperature_2m_min[index]),
          description: dayWeather.description,
          emoji: dayWeather.emoji,
        };
      }),
    };
  }
}

class WeatherApp {
  #recentSearches;

  constructor() {
    // DOM elements
    this.input = document.querySelector('#city-input');
    this.searchBtn = document.querySelector('#search-btn');
    this.loadingEl = document.querySelector('#loading');
    this.errorEl = document.querySelector('#error');
    this.errorMsg = document.querySelector('#error-message');
    this.resultEl = document.querySelector('#weather-result');
    this.currentWeatherEl = document.querySelector('#current-weather');
    this.forecastEl = document.querySelector('#forecast');
    this.recentListEl = document.querySelector('#recent-list');

    // State
    this.#recentSearches = JSON.parse(localStorage.getItem('recentSearches') || '[]');

    // Event listeners
    this.searchBtn.addEventListener('click', () => this.handleSearch());
    this.input.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') this.handleSearch();
    });
    document.querySelector('#retry-btn').addEventListener('click', () => this.handleSearch());

    // Display recent searches on load
    this.renderRecentSearches();
  }

  // UI state management
  showLoading() {
    this.loadingEl.classList.remove('hidden');
    this.errorEl.classList.add('hidden');
    this.resultEl.classList.add('hidden');
    this.searchBtn.disabled = true;
  }

  showError(message) {
    this.loadingEl.classList.add('hidden');
    this.errorEl.classList.remove('hidden');
    this.resultEl.classList.add('hidden');
    this.errorMsg.textContent = message;
    this.searchBtn.disabled = false;
  }

  showResult() {
    this.loadingEl.classList.add('hidden');
    this.errorEl.classList.add('hidden');
    this.resultEl.classList.remove('hidden');
    this.searchBtn.disabled = false;
  }

  async handleSearch() {
    const city = this.input.value.trim();
    if (!city) {
      this.showError('Please enter a city name!');
      return;
    }

    this.showLoading();

    try {
      // Step 1: Get coordinates
      const locations = await GeocodingService.searchCity(city);
      const location = locations[0]; // Use the best match

      // Step 2: Get weather for those coordinates
      const weather = await WeatherService.getWeather(
        location.latitude,
        location.longitude
      );

      // Step 3: Display results
      this.renderCurrentWeather(location, weather.current);
      this.renderForecast(weather.forecast);
      this.showResult();

      // Step 4: Save to recent searches
      this.addRecentSearch(location);

    } catch (error) {
      this.showError(error.message);
    }
  }

  renderCurrentWeather(location, current) {
    this.currentWeatherEl.innerHTML = `
      <div class="current-weather-card">
        <h2>${location.name}, ${location.country}</h2>
        ${location.state ? `<p class="state">${location.state}</p>` : ''}
        <div class="temperature">
          <span class="temp-value">${current.temperature}°C</span>
          <span class="weather-emoji">${current.emoji}</span>
        </div>
        <p class="description">${current.description}</p>
        <div class="details">
          <span>💧 Humidity: ${current.humidity}%</span>
          <span>💨 Wind: ${current.windSpeed} km/h</span>
        </div>
      </div>
    `;
  }

  renderForecast(forecast) {
    this.forecastEl.innerHTML = `
      <h3>7-Day Forecast</h3>
      <div class="forecast-grid">
        ${forecast.map(day => `
          <div class="forecast-day">
            <p class="day-name">${day.dayName}</p>
            <p class="day-emoji">${day.emoji}</p>
            <p class="day-temps">
              <span class="high">${day.maxTemp}°</span>
              <span class="low">${day.minTemp}°</span>
            </p>
          </div>
        `).join('')}
      </div>
    `;
  }

  addRecentSearch(location) {
    const entry = `${location.name}, ${location.country}`;
    this.#recentSearches = [
      entry,
      ...this.#recentSearches.filter(s => s !== entry), // Remove duplicates
    ].slice(0, 5); // Keep only 5 most recent

    localStorage.setItem('recentSearches', JSON.stringify(this.#recentSearches));
    this.renderRecentSearches();
  }

  renderRecentSearches() {
    if (this.#recentSearches.length === 0) {
      this.recentListEl.innerHTML = '<p>No recent searches</p>';
      return;
    }

    this.recentListEl.innerHTML = this.#recentSearches
      .map(city => `<button class="recent-btn" data-city="${city}">${city}</button>`)
      .join('');

    // Event delegation for recent search buttons
    this.recentListEl.addEventListener('click', (e) => {
      if (e.target.matches('.recent-btn')) {
        this.input.value = e.target.dataset.city.split(',')[0];
        this.handleSearch();
      }
    });
  }
}

