// Most APIs don't return ALL data at once — that could be millions of records!
// Instead, they return one "page" at a time.

// Common pagination patterns:

// Pattern 1: Page number + limit
async function fetchPage(page = 1, limit = 10) {
  const response = await fetch(
    `https://jsonplaceholder.typicode.com/posts?_page=${page}&_limit=${limit}`
  );

  // Some APIs include pagination info in headers
  const totalCount = response.headers.get('X-Total-Count');
  const posts = await response.json();

  return {
    data: posts,
    page,
    totalCount: parseInt(totalCount),
    totalPages: Math.ceil(totalCount / limit),
    hasMore: posts.length === limit,
  };
}

// Usage:
async function loadPostsWithPagination() {
  let currentPage = 1;

  // Load first page
  const result = await fetchPage(currentPage, 10);
  console.log(`Page ${result.page} of ${result.totalPages}`);
  console.log(`Showing ${result.data.length} of ${result.totalCount} posts`);

  // Load more button handler
  async function loadMore() {
    currentPage++;
    const moreData = await fetchPage(currentPage, 10);
    console.log(`Loaded page ${moreData.page}`);
    // Append to existing data in the DOM...

    if (!moreData.hasMore) {
      console.log('No more pages!');
      // Hide the "Load More" button
    }
  }
}

// Pattern 2: Infinite scroll (load next page when user scrolls to bottom)
class InfiniteScrollList {
  #page = 1;
  #loading = false;
  #hasMore = true;
  #container;

  constructor(containerId) {
    this.#container = document.querySelector(containerId);

    // Detect when user scrolls near the bottom
    window.addEventListener('scroll', () => {
      if (this.#loading || !this.#hasMore) return;

      const nearBottom = 
        window.innerHeight + window.scrollY >= document.body.offsetHeight - 500;

      if (nearBottom) {
        this.loadNextPage();
      }
    });

    this.loadNextPage(); // Load first page
  }

  async loadNextPage() {
    this.#loading = true;

    try {
      const result = await fetchPage(this.#page, 20);

      result.data.forEach(post => {
        const div = document.createElement('div');
        div.innerHTML = `<h3>${post.title}</h3><p>${post.body}</p>`;
        this.#container.appendChild(div);
      });

      this.#hasMore = result.hasMore;
      this.#page++;
    } catch (error) {
      console.error('Failed to load:', error);
    } finally {
      this.#loading = false;
    }
  }
}

