// === Method 2: API Key in Headers (more secure) ===
async function fetchWithHeaderKey(endpoint) {
  const response = await fetch(`https://api.example.com${endpoint}`, {
    headers: {
      'X-API-Key': API_KEY,
    },
  });
  return response.json();
}

// === Method 3: Bearer Token (OAuth / JWT) ===
// Used after a user logs in — the server gives you a token
async function fetchUserProfile(token) {
  const response = await fetch('https://api.example.com/me', {
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
  });

  if (response.status === 401) {
    // Token expired or invalid — redirect to login
    console.error('Session expired. Please log in again.');
    // window.location.href = '/login';
    return null;
  }

  return response.json();
}

// === Reusable authenticated fetch wrapper ===
function createAuthenticatedFetch(token) {
  return async function(url, options = {}) {
    const response = await fetch(url, {
      ...options,
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });

    if (response.status === 401) {
      throw new Error('Unauthorized — please log in again');
    }
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}`);
    }

    return response.json();
  };
}

