// Service class for all GitHub API interactions

class GitHubAPI {
  static BASE_URL = 'https://api.github.com';

  // Cache to avoid redundant requests
  static #cache = new Map();

  static async #fetchJSON(endpoint) {
    const cacheKey = endpoint;

    // Check cache first (with 5-minute expiry)
    if (this.#cache.has(cacheKey)) {
      const cached = this.#cache.get(cacheKey);
      if (Date.now() - cached.timestamp < 5 * 60 * 1000) {
        console.log('📦 Cache hit:', endpoint);
        return cached.data;
      }
    }

    const response = await fetch(`${this.BASE_URL}${endpoint}`, {
      headers: {
        'Accept': 'application/vnd.github.v3+json',
      },
    });

    // Handle rate limiting
    const remaining = response.headers.get('X-RateLimit-Remaining');
    if (remaining) {
      console.log(`⚡ API calls remaining: ${remaining}/60`);
    }

    if (response.status === 404) {
      throw new Error('User not found. Check the username and try again.');
    }

    if (response.status === 403) {
      const resetTime = response.headers.get('X-RateLimit-Reset');
      const resetDate = new Date(resetTime * 1000);
      throw new Error(
        `API rate limit exceeded. Try again at ${resetDate.toLocaleTimeString()}.`
      );
    }

    if (!response.ok) {
      throw new Error(`GitHub API error: ${response.status} ${response.statusText}`);
    }

    const data = await response.json();

    // Save to cache
    this.#cache.set(cacheKey, { data, timestamp: Date.now() });

    return data;
  }

  static async getUser(username) {
    const data = await this.#fetchJSON(`/users/${username}`);

    return {
      username: data.login,
      name: data.name || data.login,
      avatar: data.avatar_url,
      bio: data.bio || 'No bio provided',
      location: data.location,
      company: data.company,
      blog: data.blog,
      twitter: data.twitter_username,
      publicRepos: data.public_repos,
      followers: data.followers,
      following: data.following,
      createdAt: new Date(data.created_at),
      profileUrl: data.html_url,
    };
  }

  static async getRepos(username, sort = 'updated') {
    const data = await this.#fetchJSON(
      `/users/${username}/repos?per_page=30&sort=${sort}`
    );

    return data.map(repo => ({
      name: repo.name,
      description: repo.description || 'No description',
      language: repo.language,
      stars: repo.stargazers_count,
      forks: repo.forks_count,
      url: repo.html_url,
      updatedAt: new Date(repo.updated_at),
      isForked: repo.fork,
      topics: repo.topics || [],
    }));
  }

  // Clear the cache
  static clearCache() {
    this.#cache.clear();
    console.log('🧹 Cache cleared');
  }
}

class UIRenderer {
  static formatNumber(num) {
    if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
    if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
    return num.toString();
  }

  static formatDate(date) {
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
