class GitHubExplorer {
  #currentUser = null;
  #currentRepos = [];
  #recentSearches = [];

  constructor() {
    // DOM references
    this.searchInput = document.querySelector('#search-input');
    this.searchBtn = document.querySelector('#search-btn');
    this.loadingEl = document.querySelector('#loading');
    this.errorEl = document.querySelector('#error-container');
    this.profileEl = document.querySelector('#profile-container');
    this.reposEl = document.querySelector('#repos-container');
    this.recentEl = document.querySelector('#recent-searches');
    this.sortSelect = document.querySelector('#sort-repos');
    this.filterInput = document.querySelector('#filter-repos');

    // Load recent searches from localStorage
    this.#recentSearches = JSON.parse(
      localStorage.getItem('gh_recent') || '[]'
    );

    this.#bindEvents();
    this.#renderRecentSearches();
  }

  #bindEvents() {
    // Search
    this.searchBtn.addEventListener('click', () => this.#handleSearch());
    this.searchInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') this.#handleSearch();
    });

    // Recent searches (event delegation)
    this.recentEl.addEventListener('click', (e) => {
      if (e.target.matches('.recent-item')) {
        this.searchInput.value = e.target.dataset.username;
        this.#handleSearch();
      }
    });

    // Repo sorting
    if (this.sortSelect) {
      this.sortSelect.addEventListener('change', () => this.#sortAndRenderRepos());
    }

    // Repo filtering (with debounce!)
    if (this.filterInput) {
      let filterTimer;
      this.filterInput.addEventListener('input', () => {
        clearTimeout(filterTimer);
        filterTimer = setTimeout(() => this.#filterAndRenderRepos(), 300);
      });
    }
  }

  // ===== UI State Management =====
  #showLoading() {
    this.loadingEl.classList.remove('hidden');
    this.errorEl.classList.add('hidden');
    this.profileEl.classList.add('hidden');
    this.reposEl.classList.add('hidden');
    this.searchBtn.disabled = true;
    this.searchBtn.textContent = 'Searching...';
  }

  #showError(message) {
    this.loadingEl.classList.add('hidden');
    this.errorEl.classList.remove('hidden');
    this.errorEl.innerHTML = `
      <div class="error-box">
        <p>❌ ${message}</p>
        <button onclick="app.#handleSearch()" class="retry-btn">Try Again</button>
      </div>
    `;
    this.searchBtn.disabled = false;
    this.searchBtn.textContent = 'Search';
  }

  #showResults() {
    this.loadingEl.classList.add('hidden');
    this.errorEl.classList.add('hidden');
    this.profileEl.classList.remove('hidden');
    this.reposEl.classList.remove('hidden');
    this.searchBtn.disabled = false;
    this.searchBtn.textContent = 'Search';
  }

  // ===== Core Logic =====
  async #handleSearch() {
    const username = this.searchInput.value.trim();
    if (!username) {
      this.#showError('Please enter a GitHub username!');
      return;
    }

    this.#showLoading();

    try {
      // Fetch user profile and repos IN PARALLEL!
      const [user, repos] = await Promise.all([
        GitHubAPI.getUser(username),
        GitHubAPI.getRepos(username),
      ]);

      this.#currentUser = user;
      this.#currentRepos = repos;

      // Render profile
      this.profileEl.innerHTML = UIRenderer.renderProfile(user);

      // Render repos
      this.#sortAndRenderRepos();

      this.#showResults();

      // Save to recent searches
      this.#addRecentSearch(username, user.avatar);

    } catch (error) {
      this.#showError(error.message);
    }
  }

  #sortAndRenderRepos() {
    let repos = [...this.#currentRepos];
    const sortBy = this.sortSelect?.value || 'stars';

    switch (sortBy) {
      case 'stars':
        repos.sort((a, b) => b.stars - a.stars);
        break;
      case 'forks':
        repos.sort((a, b) => b.forks - a.forks);
        break;
      case 'updated':
        repos.sort((a, b) => b.updatedAt - a.updatedAt);
        break;
      case 'name':
        repos.sort((a, b) => a.name.localeCompare(b.name));
        break;
    }

    // Apply filter if active
    const filterText = this.filterInput?.value.toLowerCase() || '';
    if (filterText) {
      repos = repos.filter(repo =>
        repo.name.toLowerCase().includes(filterText) ||
        repo.description.toLowerCase().includes(filterText) ||
        (repo.language && repo.language.toLowerCase().includes(filterText))
      );
    }

    this.reposEl.innerHTML = `
      <h3>📁 Repositories (${repos.length})</h3>
      <div class="repo-controls">
        <select id="sort-repos">
          <option value="stars">⭐ Most Stars</option>
          <option value="forks">🍴 Most Forks</option>
          <option value="updated">🕐 Recently Updated</option>
          <option value="name">📝 Name (A-Z)</option>
        </select>
        <input type="text" id="filter-repos" placeholder="Filter repos..." 
               value="${filterText}" />
      </div>
      ${UIRenderer.renderRepoList(repos)}
    `;

    // Re-bind events for newly created elements
    this.sortSelect = document.querySelector('#sort-repos');
    this.filterInput = document.querySelector('#filter-repos');
    if (sortBy) this.sortSelect.value = sortBy;
    this.#bindEvents(); // Re-bind sort/filter events
  }

  #filterAndRenderRepos() {
    this.#sortAndRenderRepos();
  }

  // ===== Recent Searches =====
  #addRecentSearch(username, avatar) {
    this.#recentSearches = [
      { username, avatar },
      ...this.#recentSearches.filter(s => s.username !== username),
    ].slice(0, 8);

    localStorage.setItem('gh_recent', JSON.stringify(this.#recentSearches));
    this.#renderRecentSearches();
  }

  #renderRecentSearches() {
    if (this.#recentSearches.length === 0) {
      this.recentEl.innerHTML = '';
      return;
    }

    this.recentEl.innerHTML = `
      <h3>Recent Searches</h3>
      <div class="recent-grid">
        ${this.#recentSearches.map(s => `
          <button class="recent-item" data-username="${s.username}">
            <img src="${s.avatar}" alt="${s.username}" class="recent-avatar" />
            <span>${s.username}</span>
          </button>
        `).join('')}
      </div>
    `;
  }
}

