class Storage {
  // Get data with automatic JSON parsing and fallback
  static get(key, fallback = null) {
    try {
      const data = localStorage.getItem(key);
      return data ? JSON.parse(data) : fallback;
    } catch (error) {
      console.warn(`Storage.get('${key}') failed:`, error);
      return fallback;
    }
  }

  // Set data with automatic JSON stringification
  static set(key, value) {
    try {
      localStorage.setItem(key, JSON.stringify(value));
      return true;
    } catch (error) {
      // localStorage might be full (usually 5-10MB limit)
      if (error.name === 'QuotaExceededError') {
        console.error('localStorage is full! Cannot save data.');
      } else {
        console.error(`Storage.set('${key}') failed:`, error);
      }
      return false;
    }
  }

  // Remove a specific key
  static remove(key) {
    localStorage.removeItem(key);
  }

  // Check if key exists
  static has(key) {
    return localStorage.getItem(key) !== null;
  }

  // Get data with expiry (returns null if expired)
  static getWithExpiry(key) {
    const item = this.get(key);
    if (!item) return null;

    if (Date.now() > item.expiry) {
      this.remove(key);
      return null;
    }
    return item.data;
  }

  // Set data with expiry time (in milliseconds)
  static setWithExpiry(key, data, ttlMs) {
    const item = {
      data,
      expiry: Date.now() + ttlMs,
    };
    return this.set(key, item);
  }
}

