// Both apps have multiple "views" (home, detail, cart/watchlist)
// This simple router handles switching between them

class Router {
  #routes = {};
  #currentView = null;
  #contentEl;

  constructor(contentElementId) {
    this.#contentEl = document.querySelector(contentElementId);

    // Handle browser back/forward buttons
    window.addEventListener('popstate', (e) => {
      if (e.state && e.state.view) {
        this.#renderView(e.state.view, e.state.params, false);
      }
    });
  }

  // Register a view with its render function
  addRoute(viewName, renderFunction) {
    this.#routes[viewName] = renderFunction;
    return this; // Allow chaining
  }

  // Navigate to a view
  async navigate(viewName, params = {}) {
    await this.#renderView(viewName, params, true);
  }

  async #renderView(viewName, params, pushState) {
    const renderFn = this.#routes[viewName];
    if (!renderFn) {
      console.error(`Unknown view: ${viewName}`);
      return;
    }

    this.#currentView = viewName;

    // Scroll to top on view change
    window.scrollTo(0, 0);

    // Update browser history
    if (pushState) {
      history.pushState({ view: viewName, params }, '', `#${viewName}`);
    }

    // Show loading while the view renders
    this.#contentEl.innerHTML = '<div class="loading">⏳ Loading...</div>';

    try {
      const html = await renderFn(params);
      this.#contentEl.innerHTML = html;
    } catch (error) {
      this.#contentEl.innerHTML = `
        <div class="error-page">
          <h2>😕 Something went wrong</h2>
          <p>${error.message}</p>
          <button onclick="router.navigate('home')">Go Home</button>
        </div>
      `;
    }
  }

  get currentView() {
    return this.#currentView;
  }
}

