class MovieAPI {
  // Replace with your TMDB API key
  static API_KEY = 'YOUR_API_KEY_HERE';
  static BASE_URL = 'https://api.themoviedb.org/3';
  static IMG_BASE = 'https://image.tmdb.org/t/p';

  // Image URL helpers
  static posterURL(path, size = 'w500') {
    return path ? `${this.IMG_BASE}/${size}${path}` : '/assets/no-poster.png';
  }

  static backdropURL(path, size = 'w1280') {
    return path ? `${this.IMG_BASE}/${size}${path}` : '';
  }

  // Core fetch method with caching and error handling
  static async #fetchTMDB(endpoint, params = {}) {
    const queryParams = new URLSearchParams({
      api_key: this.API_KEY,
      language: 'en-US',
      ...params,
    });

    const url = `${this.BASE_URL}${endpoint}?${queryParams}`;
    const cacheKey = `tmdb_${endpoint}_${queryParams}`;

    // Check cache (5-minute expiry)
    const cached = Storage.getWithExpiry(cacheKey);
    if (cached) return cached;

    const response = await fetch(url);

    if (!response.ok) {
      if (response.status === 401) throw new Error('Invalid API key. Check your TMDB configuration.');
      if (response.status === 404) throw new Error('Content not found.');
      if (response.status === 429) throw new Error('Too many requests. Please wait a moment.');
      throw new Error(`TMDB API error: ${response.status}`);
    }

    const data = await response.json();

    // Cache for 5 minutes
    Storage.setWithExpiry(cacheKey, data, 5 * 60 * 1000);

    return data;
  }

  // ===== PUBLIC METHODS =====

  static async getTrending(timeWindow = 'week', page = 1) {
    const data = await this.#fetchTMDB('/trending/movie/' + timeWindow, { page });
    return {
      movies: data.results.map(m => this.#transformMovie(m)),
      totalPages: data.total_pages,
      currentPage: data.page,
    };
  }

  static async getPopular(page = 1) {
    const data = await this.#fetchTMDB('/movie/popular', { page });
    return {
      movies: data.results.map(m => this.#transformMovie(m)),
      totalPages: data.total_pages,
      currentPage: data.page,
    };
  }

  static async getTopRated(page = 1) {
    const data = await this.#fetchTMDB('/movie/top_rated', { page });
    return {
      movies: data.results.map(m => this.#transformMovie(m)),
      totalPages: data.total_pages,
      currentPage: data.page,
    };
  }

  static async searchMovies(query, page = 1) {
    if (!query.trim()) return { movies: [], totalPages: 0, currentPage: 1 };
    const data = await this.#fetchTMDB('/search/movie', { query, page });
    return {
      movies: data.results.map(m => this.#transformMovie(m)),
      totalPages: data.total_pages,
      totalResults: data.total_results,
      currentPage: data.page,
    };
  }

  static async getMovieDetails(movieId) {
    const data = await this.#fetchTMDB(`/movie/${movieId}`, {
      append_to_response: 'credits,videos,similar,reviews',
    });
    return this.#transformMovieDetail(data);
  }

  static async getGenres() {
    const data = await this.#fetchTMDB('/genre/movie/list');
    return data.genres; // [{ id: 28, name: 'Action' }, ...]
  }

  // Transform raw API data into clean format
  static #transformMovie(raw) {
    return {
      id: raw.id,
      title: raw.title,
      overview: Utils.truncate(raw.overview, 150),
      fullOverview: raw.overview,
      poster: this.posterURL(raw.poster_path),
      backdrop: this.backdropURL(raw.backdrop_path),
      rating: Math.round(raw.vote_average * 10) / 10,
      voteCount: raw.vote_count,
      releaseDate: raw.release_date,
      releaseYear: raw.release_date ? new Date(raw.release_date).getFullYear() : 'N/A',
      genreIds: raw.genre_ids || [],
      popularity: raw.popularity,
    };
  }

  static #transformMovieDetail(raw) {
    return {
      ...this.#transformMovie(raw),
      overview: raw.overview, // Full overview for detail page
      tagline: raw.tagline,
      runtime: raw.runtime,
      budget: raw.budget,
      revenue: raw.revenue,
      genres: raw.genres.map(g => g.name),
      status: raw.status,
      cast: raw.credits?.cast?.slice(0, 12).map(c => ({
        id: c.id,
        name: c.name,
        character: c.character,
        photo: this.posterURL(c.profile_path, 'w185'),
      })) || [],
      trailer: raw.videos?.results?.find(
        v => v.type === 'Trailer' && v.site === 'YouTube'
      ) || null,
      similar: raw.similar?.results?.slice(0, 6).map(m => this.#transformMovie(m)) || [],
      reviews: raw.reviews?.results?.slice(0, 5).map(r => ({
        author: r.author,
        content: Utils.truncate(r.content, 300),
        rating: r.author_details?.rating,
        date: r.created_at,
      })) || [],
    };
  }
}

