class MovieRenderer {
  static renderMovieCard(movie, isInWatchlist = false) {
    return `
      <div class="movie-card" data-movie-id="${movie.id}">
        <div class="movie-poster">
          <img src="${movie.poster}" alt="${Utils.escapeHTML(movie.title)}"
               loading="lazy" />
          <div class="movie-overlay">
            <button class="watchlist-btn ${isInWatchlist ? 'in-watchlist' : ''}"
                    data-action="toggle-watchlist" data-movie-id="${movie.id}"
                    title="${isInWatchlist ? 'Remove from' : 'Add to'} Watchlist">
              ${isInWatchlist ? '❤️' : '🤍'}
            </button>
            <div class="movie-rating">
              <span class="stars">${Utils.renderStars(movie.rating / 2)}</span>
              <span class="rating-number">${movie.rating}</span>
            </div>
          </div>
        </div>
        <div class="movie-info">
          <h3 class="movie-title">${Utils.escapeHTML(movie.title)}</h3>
          <p class="movie-year">${movie.releaseYear}</p>
        </div>
      </div>
    `;
  }

  static renderMovieGrid(movies, watchlist = []) {
    if (movies.length === 0) {
      return '<div class="empty-state"><h3>🎬 No movies found</h3><p>Try a different search term.</p></div>';
    }
    const watchlistIds = new Set(watchlist.map(m => m.id));
    return `
      <div class="movie-grid">
        ${movies.map(movie => 
          this.renderMovieCard(movie, watchlistIds.has(movie.id))
        ).join('')}
      </div>
    `;
  }

  static renderHomePage(trending, popular, genres) {
    return `
      <section class="hero">
        <div class="hero-content">
          <h1>🎬 CineVerse</h1>
          <p>Discover your next favorite movie</p>
          <div class="search-container">
            <input type="text" id="search-input" 
                   placeholder="Search movies..." autocomplete="off" />
            <div id="search-suggestions" class="hidden"></div>
          </div>
        </div>
      </section>

      <section class="genre-filter">
        <h2>Browse by Genre</h2>
        <div class="genre-chips">
          <button class="genre-chip active" data-genre="all">All</button>
          ${genres.map(g => `
            <button class="genre-chip" data-genre="${g.id}">${g.name}</button>
          `).join('')}
        </div>
      </section>

      <section class="movie-section">
        <h2>🔥 Trending This Week</h2>
        ${this.renderMovieGrid(trending)}
      </section>

      <section class="movie-section">
        <h2>⭐ Popular Movies</h2>
        ${this.renderMovieGrid(popular)}
