// The App Controller wires it all together:
class CineVerseApp {
  #watchlist;
  #currentPage = 1;
  #genres = [];

  constructor() {
    this.router = new Router('#app-content');
    this.#watchlist = Storage.get('cineverse_watchlist', []);

    this.router
      .addRoute('home', () => this.#renderHome())
      .addRoute('search', (p) => this.#renderSearchResults(p.query))
      .addRoute('movie', (p) => this.#renderMovieDetail(p.id))
      .addRoute('watchlist', () => this.#renderWatchlistPage());

    this.#init();
  }

  async #init() {
    // Load genres once on startup
    this.#genres = await MovieAPI.getGenres();

    // Start on home page
    await this.router.navigate('home');

    // Global event delegation
    document.querySelector('#app-content').addEventListener('click', (e) => {
      this.#handleGlobalClick(e);
    });
  }

  async #renderHome() {
    const [trending, popular] = await Promise.all([
      MovieAPI.getTrending(),
      MovieAPI.getPopular(),
    ]);

    const html = MovieRenderer.renderHomePage(
      trending.movies, popular.movies, this.#genres
    );

    // Set up search after render
    setTimeout(() => this.#setupSearch(), 0);

    return html;
  }

  #setupSearch() {
    const input = document.querySelector('#search-input');
    if (!input) return;

    const debouncedSearch = Utils.debounce(async (query) => {
      if (query.length < 2) return;
      await this.router.navigate('search', { query });
    }, 400);

    input.addEventListener('input', (e) => debouncedSearch(e.target.value));
    input.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' && e.target.value.trim()) {
        this.router.navigate('search', { query: e.target.value.trim() });
      }
    });
  }

  #handleGlobalClick(e) {
    // Movie card click → navigate to detail
    const movieCard = e.target.closest('.movie-card');
    if (movieCard && !e.target.closest('.watchlist-btn')) {
      const movieId = movieCard.dataset.movieId;
      this.router.navigate('movie', { id: movieId });
      return;
    }

    // Watchlist toggle
    if (e.target.closest('[data-action="toggle-watchlist"]')) {
      e.stopPropagation();
      const btn = e.target.closest('[data-action="toggle-watchlist"]');
      this.#toggleWatchlist(parseInt(btn.dataset.movieId));
    }
  }

  // ...more methods in the next lessons!
}

