class WatchlistManager {
  #items;
  #storageKey;
  #onChange;

  constructor(storageKey = 'cineverse_watchlist', onChange = () => {}) {
    this.#storageKey = storageKey;
    this.#onChange = onChange;
    this.#items = Storage.get(storageKey, []);
  }

  add(movie) {
    if (this.has(movie.id)) return false;

    // Store only essential data (not the full API response)
    this.#items.unshift({
      id: movie.id,
      title: movie.title,
      poster: movie.poster,
      rating: movie.rating,
      releaseYear: movie.releaseYear,
      addedAt: Date.now(),
    });

    this.#save();
    Toast.success(`"${movie.title}" added to watchlist!`);
    return true;
  }

  remove(movieId) {
    const movie = this.#items.find(m => m.id === movieId);
    if (!movie) return false;

    this.#items = this.#items.filter(m => m.id !== movieId);
    this.#save();
    Toast.info(`"${movie.title}" removed from watchlist.`);
    return true;
  }

  toggle(movie) {
    if (this.has(movie.id)) {
      this.remove(movie.id);
      return false; // Not in watchlist anymore
    } else {
      this.add(movie);
      return true; // Now in watchlist
    }
  }

  has(movieId) {
    return this.#items.some(m => m.id === movieId);
  }

  getAll() {
    return [...this.#items]; // Return a copy
  }

  get count() {
    return this.#items.length;
  }

  #save() {
    Storage.set(this.#storageKey, this.#items);
    this.#onChange(this.#items); // Notify the app of changes
  }
}

