async #handleGenreFilter(genreId) {
  // Update active chip UI
  document.querySelectorAll('.genre-chip').forEach(chip => {
    chip.classList.toggle('active', chip.dataset.genre === String(genreId));
  });

  if (genreId === 'all') {
    // Reload default view
    await this.router.navigate('home');
    return;
  }

  // TMDB supports genre filtering via discover endpoint
  const params = new URLSearchParams({
    api_key: MovieAPI.API_KEY,
    with_genres: genreId,
    sort_by: 'popularity.desc',
    page: 1,
  });

  const response = await fetch(
    `https://api.themoviedb.org/3/discover/movie?${params}`
  );
  const data = await response.json();

  const movies = data.results.map(m => MovieAPI.posterURL ? 
    { ...m, poster: MovieAPI.posterURL(m.poster_path), 
      releaseYear: m.release_date ? new Date(m.release_date).getFullYear() : 'N/A',
      rating: Math.round(m.vote_average * 10) / 10 } : m
  );

  const grid = document.querySelector('.movie-grid');
  const section = document.querySelector('.movie-section');
  if (grid && section) {
    section.querySelector('h2').textContent = 
      `${this.#genres.find(g => g.id === parseInt(genreId))?.name || 'Filtered'} Movies`;
    grid.innerHTML = movies.map(m => 
      MovieRenderer.renderMovieCard(m, this.watchlist.has(m.id))
    ).join('');
  }
}

async #loadMoreMovies() {
  const btn = document.querySelector('#load-more-btn');
  btn.textContent = '⏳ Loading...';
  btn.disabled = true;

  try {
    this.#currentPage++;
    const result = await MovieAPI.getPopular(this.#currentPage);

    const grid = document.querySelector('.movie-grid:last-of-type');
    if (grid) {
      const newCards = result.movies.map(m => 
        MovieRenderer.renderMovieCard(m, this.watchlist.has(m.id))
      ).join('');
      grid.insertAdjacentHTML('beforeend', newCards);
    }

    if (this.#currentPage >= result.totalPages) {
      btn.textContent = 'No More Movies';
      btn.disabled = true;
    } else {
      btn.textContent = 'Load More Movies';
      btn.disabled = false;
    }
  } catch (error) {
    btn.textContent = 'Failed — Retry';
    btn.disabled = false;
    this.#currentPage--; // Revert page increment
    Toast.error('Failed to load more movies.');
  }
}

class ProductAPI {
  static BASE_URL = 'https://dummyjson.com';

  static async #fetchJSON(endpoint) {
    const cacheKey = `shop_${endpoint}`;
    const cached = Storage.getWithExpiry(cacheKey);
    if (cached) return cached;

    const response = await fetch(`${this.BASE_URL}${endpoint}`);
    if (!response.ok) {
      throw new Error(`API Error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json();
    Storage.setWithExpiry(cacheKey, data, 10 * 60 * 1000); // 10 min cache
    return data;
  }

  static async getAllProducts(limit = 30, skip = 0) {
    const data = await this.#fetchJSON(`/products?limit=${limit}&skip=${skip}`);
    return {
      products: data.products.map(p => this.#transform(p)),
      total: data.total,
      hasMore: skip + limit < data.total,
    };
  }

  static async getProduct(id) {
    const data = await this.#fetchJSON(`/products/${id}`);
    return this.#transform(data);
  }

  static async getCategories() {
    return this.#fetchJSON('/products/categories');
  }

  static async getByCategory(category, limit = 30) {
    const data = await this.#fetchJSON(
      `/products/category/${category}?limit=${limit}`
    );
    return {
      products: data.products.map(p => this.#transform(p)),
      total: data.total,
    };
  }

  static async searchProducts(query) {
    const data = await this.#fetchJSON(`/products/search?q=${encodeURIComponent(query)}`);
    return {
      products: data.products.map(p => this.#transform(p)),
      total: data.total,
    };
  }

  static #transform(raw) {
    return {
      id: raw.id,
      title: raw.title,
      description: raw.description,
      price: raw.price,
      discountPercentage: raw.discountPercentage,
      discountedPrice: Math.round(raw.price * (1 - raw.discountPercentage / 100) * 100) / 100,
      rating: Math.round(raw.rating * 10) / 10,
      stock: raw.stock,
      brand: raw.brand || 'Unknown',
      category: raw.category,
      thumbnail: raw.thumbnail,
      images: raw.images || [raw.thumbnail],
      inStock: raw.stock > 0,
    };
  }
}

class ProductFilter {
  static sort(products, sortBy) {
    const sorted = [...products];

    switch (sortBy) {
      case 'price-low':
        return sorted.sort((a, b) => a.discountedPrice - b.discountedPrice);
      case 'price-high':
        return sorted.sort((a, b) => b.discountedPrice - a.discountedPrice);
      case 'rating':
        return sorted.sort((a, b) => b.rating - a.rating);
      case 'name':
        return sorted.sort((a, b) => a.title.localeCompare(b.title));
      case 'featured':
      default:
        return sorted; // Default API order
    }
  }

  static filterByPrice(products, minPrice, maxPrice) {
    return products.filter(p => {
      const price = p.discountedPrice;
      if (minPrice && price < minPrice) return false;
      if (maxPrice && price > maxPrice) return false;
      return true;
    });
  }

  static search(products, query) {
    if (!query.trim()) return products;
    const q = query.toLowerCase();
    return products.filter(p =>
      p.title.toLowerCase().includes(q) ||
      p.description.toLowerCase().includes(q) ||
      p.brand.toLowerCase().includes(q) ||
      p.category.toLowerCase().includes(q)
    );
  }

  // Apply all filters at once
  static apply(products, { sortBy, minPrice, maxPrice, searchQuery }) {
    let filtered = [...products];

    if (searchQuery) {
      filtered = this.search(filtered, searchQuery);
    }

    if (minPrice || maxPrice) {
      filtered = this.filterByPrice(filtered, minPrice, maxPrice);
    }

    return this.sort(filtered, sortBy);
  }
}

class CartManager {
  #items;
  #storageKey;
  #onChange;

  constructor(storageKey = 'shopsmart_cart', onChange = () => {}) {
    this.#storageKey = storageKey;
    this.#onChange = onChange;
    this.#items = Storage.get(storageKey, []);
  }

  addItem(product, quantity = 1) {
    if (!product.inStock) {
      Toast.error('This product is out of stock!');
      return false;
    }

    const existingIndex = this.#items.findIndex(item => item.product.id === product.id);

    if (existingIndex !== -1) {
      // Product already in cart — increase quantity
      const newQty = this.#items[existingIndex].quantity + quantity;
      if (newQty > product.stock) {
        Toast.warning(`Only ${product.stock} items available.`);
        this.#items[existingIndex].quantity = product.stock;
      } else {
        this.#items[existingIndex].quantity = newQty;
      }
    } else {
      // New product
      this.#items.push({
        product: {
          id: product.id,
          title: product.title,
          price: product.price,
          discountedPrice: product.discountedPrice,
          thumbnail: product.thumbnail,
          stock: product.stock,
          brand: product.brand,
        },
        quantity: Math.min(quantity, product.stock),
      });
    }

    this.#save();
    Toast.success(`"${product.title}" added to cart!`);
    return true;
  }

  removeItem(productId) {
    const item = this.#items.find(i => i.product.id === productId);
    if (!item) return;

    this.#items = this.#items.filter(i => i.product.id !== productId);
    this.#save();
    Toast.info(`"${item.product.title}" removed from cart.`);
  }

  updateQuantity(productId, quantity) {
    const item = this.#items.find(i => i.product.id === productId);
    if (!item) return;

    if (quantity <= 0) {
      this.removeItem(productId);
      return;
    }

    if (quantity > item.product.stock) {
      Toast.warning(`Only ${item.product.stock} available.`);
      item.quantity = item.product.stock;
    } else {
      item.quantity = quantity;
    }

    this.#save();
  }

  getItems() {
    return [...this.#items];
  }

  get itemCount() {
    return this.#items.reduce((sum, item) => sum + item.quantity, 0);
  }

  get subtotal() {
    return this.#items.reduce(
      (sum, item) => sum + (item.product.discountedPrice * item.quantity), 0
    );
  }

  get savings() {
    return this.#items.reduce(
      (sum, item) => sum + ((item.product.price - item.product.discountedPrice) * item.quantity), 0
    );
  }

  get tax() {
    return Math.round(this.subtotal * 0.08 * 100) / 100; // 8% tax
  }

  get total() {
    return Math.round((this.subtotal + this.tax) * 100) / 100;
  }

  get isEmpty() {
    return this.#items.length === 0;
  }

  clear() {
    this.#items = [];
    this.#save();
    Toast.info('Cart cleared.');
  }

  #save() {
    Storage.set(this.#storageKey, this.#items);
    this.#onChange(this); // Pass the entire cart for UI updates
  }
}

