import { useState, useEffect } from 'react';

function MovieSearch() {
  // State management — like our class properties
  const [query, setQuery] = useState('');
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);

  // Side effect — like our event listeners and fetch calls
  useEffect(() => {
    if (query.length < 2) return;

    const timer = setTimeout(async () => {  // Debounce!
      setLoading(true);
      try {
        const response = await fetch(                // fetch!
          `https://api.themoviedb.org/3/search/movie?query=${query}`
        );
        const data = await response.json();          // JSON parsing!
        setMovies(data.results);                     // Array of objects!
      } catch (error) {
        console.error(error);                        // Error handling!
      } finally {
        setLoading(false);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query]);

  // JSX — like our template literals, but with real components
  return (
    <div>
      <input 
        value={query}
        onChange={(e) => setQuery(e.target.value)}   // Events!
        placeholder="Search movies..."
      />
      {loading && <p>Loading...</p>}
      <div className="grid">
        {movies.map(movie => (                        // .map()!
          <div key={movie.id} className="card">
            <h3>{movie.title}</h3>
            <p>⭐ {movie.vote_average}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

